  function getState(){
    const ids = [
      'make','model','lens','focal','aperture','shutter','iso','date','time',
      'title','location','project','rating','thought','note','promptText','creator','watermarkText',
      'theme','customLogoDataUrl','customLogoFileName','titleFont','bodyFont','metaFont','textColorMode','titleColor','bodyColor','metaColor','locationColor','posterTitleDirection','posterBodyDirection','posterTitleSize','posterBodySize','posterTitleX','posterTitleY','posterBodyX','posterBodyY','titleScale','titleOffsetX','titleOffsetY','bodyScale','bodyOffsetX','bodyOffsetY','locationScale','locationOffsetX','locationOffsetY','exifScale','exifOffsetX','exifOffsetY','frameColor','margin','radius','brushStyle','multiFrameLayout','multiFrameGap','creatorFormat','creatorColor','watermarkColor'
    ];
    const state = { layout, batchApplyMode, elementLayoutState: JSON.parse(JSON.stringify(elementLayoutState)) };
    ids.forEach(id => state[id] = $(id).value);
    ['showTitle','showLocation','showThought','showNote','showProject','showRating','showPrompt','showLogo','showExif','showCreator','showWatermark']
      .forEach(id => state[id] = $(id).checked);
    state.watermarkDataUrl = virtualTextValues.watermarkDataUrl || '';
    state.watermarkFileName = virtualTextValues.watermarkFileName || '';
    return state;
  }

  function saveState(){
    try{ localStorage.setItem('framenote-v248-state', JSON.stringify(getState())); }catch(e){}
  }

  function restoreState(){
    try{
      const s = JSON.parse(localStorage.getItem('framenote-v248-state') || localStorage.getItem('framenote-v247-state') || localStorage.getItem('framenote-v246-state') || localStorage.getItem('framenote-v245-state') || localStorage.getItem('framenote-v241-state') || localStorage.getItem('framenote-v240-state') || localStorage.getItem('framenote-v239-state') || localStorage.getItem('framenote-v234-state') || localStorage.getItem('framenote-v233-state') || 'null');
      if(!s) return;
      Object.entries(s).forEach(([k,v]) => {
        if(k === 'layout'){ layout = v === 'polaroid' ? 'brush' : v; return; }
        if(k === 'batchApplyMode'){ batchApplyMode = v !== false; return; }
        if(k === 'elementLayoutState'){ elementLayoutState = v && typeof v === 'object' ? v : {}; return; }
        const el = $(k); if(!el) return;
        if(el.type === 'checkbox') el.checked = !!v;
        else el.value = v;
      });
    }catch(e){}
  }

  function normalizeFontSelections(){
    const defaults = {
      titleFont: "'Pretendard', sans-serif",
      bodyFont: "'Source Han Sans KR', 'Noto Sans KR', sans-serif",
      metaFont: "'Pretendard', sans-serif"
    };
    Object.entries(defaults).forEach(([id, fallback]) => {
      const select = $(id);
      const exists = [...select.options].some(option => option.value === select.value);
      if(!exists) select.value = fallback;
    });
  }

  function waitForFonts(timeoutMs=3500){
    return Promise.race([
      document.fonts.ready,
      new Promise(resolve => setTimeout(resolve, timeoutMs))
    ]);
  }

  function layoutConfigFor(source=layout){
    const layoutName = typeof source === 'string'
      ? source
      : (source && source.layout ? source.layout : layout);
    return LAYOUT_CONFIG[layoutName] || LAYOUT_CONFIG.journal;
  }

  function activeLayoutConfig(){
    return layoutConfigFor(layout);
  }

  function isActiveSetting(state, name){
    return layoutConfigFor(state).settings.includes(name) && !!state[name];
  }

  function exifManufacturerTheme(state){
    const make = String(state?.make || '').trim();
    const model = String(state?.model || '').trim();
    const label = make || model || 'CAMERA';
    return {
      key:'exif_text',
      brand:label,
      accent:state?.metaColor || '#5f5f5f',
      textOnly:true
    };
  }

  function customManufacturerTheme(state){
    const label = String(state?.make || state?.model || state?.customLogoFileName || 'CAMERA').trim();
    const dataUrl = String(state?.customLogoDataUrl || '').trim();
    if(!dataUrl) return exifManufacturerTheme(state);
    return {
      key:'custom_logo',
      brand:label,
      accent:state?.metaColor || '#5f5f5f',
      dataUrl,
      custom:true
    };
  }

  function effectiveTheme(state){
    if(state.theme === 'custom_logo') return customManufacturerTheme(state);
    if(state.theme === 'exif_text') return exifManufacturerTheme(state);
    if(state.theme !== 'auto') return BRANDS[state.theme] || exifManufacturerTheme(state);
    const text = `${state.make} ${state.model}`.toLowerCase();
    if(text.includes('fuji')) return BRANDS.fujifilm;
    if(text.includes('leica')) return BRANDS.leica;
    if(text.includes('canon')) return BRANDS.canon;
    if(text.includes('nikon')) return BRANDS.nikon;
    if(text.includes('sony')) return BRANDS.sony;
    if(text.includes('panasonic') || text.includes('lumix')) return BRANDS.lumix;
    if(text.includes('olympus') || text.includes('om system')) return BRANDS.om;
    if(text.includes('ricoh')) return BRANDS.ricoh;
    return exifManufacturerTheme(state);
  }

  function stylesForLayout(lay){
    const frameColorInput = $('frameColor');
    const hint = $('styleConstraintHint');
    const disabled = (lay === 'contact' || lay === 'stamp');
    frameColorInput.disabled = disabled;

    if(lay === 'contact'){
      hint.textContent = 'Contact Sheet C는 필름 시트 스타일로 고정되어 프레임 색상 수정이 비활성화됩니다.';
    } else if(lay === 'stamp'){
      hint.textContent = 'Film Date Overlay는 프레임 없는 사진 위 오버레이이므로 프레임 색상 수정이 비활성화됩니다.';
    } else if(lay === 'poster'){
      hint.textContent = 'Poster Overlay는 사진 위 텍스트 중심 레이아웃입니다.';
    } else if(lay === 'frameonly'){
      hint.textContent = 'Clean Frame은 사진과 프레임만 표시합니다.';
    } else if(lay === 'minimal'){
      hint.textContent = 'Minimal Bottom Bar는 사진 아래 얇은 정보 바를 사용합니다.';
    } else if(lay === 'caption'){
      hint.textContent = 'Exhibition Caption은 사진 아래에 전시 캡션 형식의 설명을 배치합니다.';
    } else if(lay === 'brush'){
      hint.textContent = 'Brush Photo Edge는 사진의 네 면을 선택한 붓질 스타일로 마스킹하며, 프레임 색상은 바깥 캔버스 색으로 사용됩니다.';
    } else if(lay === 'photodata'){
      hint.textContent = 'Photo Data는 사진 비율에 맞춰 레이아웃을 자동 전환하고 실제 RGB 히스토그램·대표 색상·밝기·EXIF를 표시합니다.';
    } else if(lay === 'multiframe'){
      hint.textContent = 'Multi Frame은 원본 사진 비율을 유지하며 여러 장을 심플하게 배치합니다. 텍스트나 EXIF 없이 전체 프레임 비율에 집중합니다.';
    } else {
      hint.textContent = '현재 레이아웃은 프레임 색상 수정 가능.';
    }
  }

  function updateTextColorControls(){
    const cfg = activeLayoutConfig();
    const supportedColors = cfg.colors || [];
    const hasEditableColors = supportedColors.length > 0;
    const custom = $('textColorMode').value === 'custom';

    const modeLabel = document.querySelector('[data-color-mode]');
    if(modeLabel){
      modeLabel.classList.toggle('hidden-control', !hasEditableColors);
    }
    $('textColorMode').disabled = !hasEditableColors;

    document.querySelectorAll('[data-color-control]').forEach(label => {
      const colorType = label.dataset.colorControl;
      const supported = supportedColors.includes(colorType);
      label.classList.toggle('hidden-control', !supported);
      label.classList.toggle('color-control-disabled', supported && !custom);

      const input = label.querySelector('input');
      if(input){
        input.disabled = !supported || !custom;
      }
    });
  }

  function updateCustomBrandLogoUI(){
    const fileName = String($('customLogoFileName')?.value || '').trim();
    const hasLogo = !!String($('customLogoDataUrl')?.value || '').trim();
    const status = $('customBrandLogoStatus');
    const clearButton = $('clearCustomBrandLogoBtn');
    if(status){
      status.textContent = hasLogo
        ? `추가한 제조사 로고: ${fileName || '사용자 로고'}`
        : '추가한 제조사 로고 없음';
    }
    if(clearButton) clearButton.disabled = !hasLogo;
  }

  function updateControlVisibility(){
    const cfg = activeLayoutConfig();
    const supportsBrand = cfg.settings.includes('showLogo');
    const supportsImageLogo = cfg.imageLogo === true;
    document.querySelectorAll('[data-brand-control]').forEach(el => {
      el.classList.toggle('hidden-control', !supportsBrand);
    });
    document.querySelectorAll('[data-custom-logo-control]').forEach(el => {
      el.classList.toggle('hidden-control', !supportsImageLogo);
    });
    updateCustomBrandLogoUI();

    const displayOptions = $('displayOptions');
    if(displayOptions) displayOptions.style.display = 'grid';

    document.querySelectorAll('[data-setting]').forEach(el => {
      el.classList.toggle('hidden-control', !cfg.settings.includes(el.dataset.setting));
    });

    document.querySelectorAll('[data-text]').forEach(el => {
      el.classList.toggle('hidden-control', !cfg.texts.includes(el.dataset.text));
    });

    const currentTheme = effectiveTheme(getState());
    $('brandToggleText').textContent = (layout === 'stamp' || currentTheme.textOnly) ? '브랜드명' : '브랜드 로고';

    document.querySelectorAll('[data-poster-control]').forEach(el => {
      el.classList.toggle('hidden-control', layout !== 'poster');
    });
    document.querySelectorAll('[data-brush-control]').forEach(el => {
      el.classList.toggle('hidden-control', layout !== 'brush');
    });
    document.querySelectorAll('[data-multiframe-control]').forEach(el => {
      el.classList.toggle('hidden-control', layout !== 'multiframe');
    });
    document.querySelectorAll('[data-radius-control]').forEach(el => {
      el.classList.toggle('hidden-control', layout === 'brush' || layout === 'multiframe');
    });

    renderElementControls();
    updateTextColorControls();
  }

  function photoRatio(){
    if(imageLoaded && image.naturalWidth && image.naturalHeight) return image.naturalWidth / image.naturalHeight;
    return 3/2;
  }

  const EXIF_FIELD_IDS = ['make','model','lens','focal','aperture','shutter','iso','date','time'];
  const EXIF_FIELD_SET = new Set(EXIF_FIELD_IDS);


function clonePlain(value){
  return JSON.parse(JSON.stringify(value));
}

function captureDesignState(){
  const state = {
    layout,
    elementLayoutState: clonePlain(elementLayoutState)
  };
  DESIGN_VALUE_FIELD_IDS.forEach(id => {
    const element = $(id);
    state[id] = element ? element.value : '';
  });
  DESIGN_CHECK_FIELD_IDS.forEach(id => {
    const element = $(id);
    state[id] = !!element?.checked;
  });
  return state;
}

function applyDesignState(design, {render=false, save=false} = {}){
  if(!design) return;
  layout = design.layout === 'polaroid' ? 'brush' : (design.layout || 'journal');
  elementLayoutState = clonePlain(design.elementLayoutState || {});

  DESIGN_VALUE_FIELD_IDS.forEach(id => {
    const element = $(id);
    if(element && design[id] != null) element.value = design[id];
  });
  DESIGN_CHECK_FIELD_IDS.forEach(id => {
    const element = $(id);
    if(element && design[id] != null) element.checked = !!design[id];
  });

  normalizeFontSelections();
  document.querySelectorAll('.template').forEach(button => {
    button.classList.toggle('active', button.dataset.layout === layout);
  });
  stylesForLayout(layout);
  renderedElementLayout = null;
  updateControlVisibility();
  renderElementControls(true);
  if(save) saveState();
  if(render) renderPreview();
}

function syncDesignStateAfterChange({refreshList=false} = {}){
  const design = captureDesignState();
  if(batchApplyMode){
    photoItems.forEach(item => { item.designState = clonePlain(design); });
  }else{
    const item = getSelectedPhotoItem();
    if(item) item.designState = clonePlain(design);
  }
  if(refreshList) renderBatchList();
}

function updateBatchModeUI(){
  const toggle = $('batchApplyToggle');
  const panel = $('batchModePanel');
  const title = $('batchModeTitle');
  const description = $('batchModeDescription');
  if(toggle) toggle.checked = batchApplyMode;
  if(panel) panel.classList.toggle('individual', !batchApplyMode);
  if(title) title.textContent = batchApplyMode ? '일괄 적용 모드' : '개별 작업 모드';
  if(description){
    description.textContent = batchApplyMode
      ? '템플릿·스타일·표시 요소·요소 배치를 모든 사진에 동일하게 적용합니다.'
      : '선택한 사진에만 템플릿과 스타일을 저장합니다. 사진을 전환하면 각 설정이 복원됩니다.';
  }
}

async function setBatchApplyMode(enabled){
  syncCurrentPhotoValues();
  const currentDesign = captureDesignState();
  batchApplyMode = !!enabled;

  // 모드를 전환하는 시점의 현재 디자인을 모든 사진의 시작점으로 맞춘다.
  // 이후 일괄 모드에서는 계속 함께 변경되고, 개별 모드에서는 사진별로 분리된다.
  photoItems.forEach(item => { item.designState = clonePlain(currentDesign); });

  updateBatchModeUI();
  renderBatchList();
  saveState();
  $('statusText').textContent = batchApplyMode ? '일괄 적용 모드' : '개별 작업 모드';
}

const virtualTextValues = {watermarkDataUrl:'', watermarkFileName:''};

function captureTextValues(){
  const values = {};
  TEXT_FIELD_IDS.forEach(id => {
    const element = $(id);
    values[id] = element ? element.value : (virtualTextValues[id] || '');
  });
  return values;
}

function setTextValues(values, {render=true, save=true} = {}){
  TEXT_FIELD_IDS.forEach(id => {
    const element = $(id);
    if(element) element.value = values && values[id] != null ? values[id] : ''; else virtualTextValues[id] = values && values[id] != null ? values[id] : '';
  });
  const watermarkLabel = $('watermarkFileName');
  if(watermarkLabel) watermarkLabel.textContent = virtualTextValues.watermarkFileName ? `불러온 워터마크: ${virtualTextValues.watermarkFileName}` : '불러온 워터마크 없음';
  if(save) saveState();
  if(render) renderPreview();
}

function capturePhotoFieldValues(){
  return {
    textValues: captureTextValues(),
    exifValues: captureExifValues()
  };
}

function applyPhotoFieldValues(payload, {render=true, save=true} = {}){
  setTextValues(payload && payload.textValues ? payload.textValues : {}, {render:false, save:false});
  setExifValues(payload && payload.exifValues ? payload.exifValues : {}, {render:false, save:false});
  if(save) saveState();
  if(render) renderPreview();
}

function getSelectedPhotoItem(){
  return photoItems.find(item => item.id === selectedPhotoId) || null;
}

function syncCurrentPhotoValues(){
  const item = getSelectedPhotoItem();
  if(!item) return;
  item.textValues = captureTextValues();
  item.exifValues = captureExifValues();
  if(!batchApplyMode){
    item.designState = clonePlain(captureDesignState());
  }
}

function renderBatchList(){
  const list = $('batchList');
  const countEl = $('batchCount');
  if(countEl) countEl.textContent = `${photoItems.length}장`;
  if(!list) return;

  if(!photoItems.length){
    list.innerHTML = '<div class="batch-note">아직 불러온 사진이 없습니다.</div>';
    return;
  }

  list.innerHTML = photoItems.map((item, index) => {
    const sizeText = item.width && item.height ? `${item.width} × ${item.height}` : '해상도 읽는 중…';
    const exifBadge = item.hasExif ? 'EXIF' : 'NO EXIF';
    const active = item.id === selectedPhotoId ? ' active' : '';
    const safeName = escapeHtml(item.name || `photo_${index+1}`);
    const itemLayout = batchApplyMode ? layout : (item.designState?.layout || layout);
    const layoutLabel = LAYOUT_LABELS[itemLayout] || itemLayout;
    const modeLabel = batchApplyMode ? '일괄' : '개별';
    return `<button class="batch-item${active}" type="button" data-photo-id="${item.id}">
      <span class="batch-item-name">${index + 1}. ${safeName}</span>
      <span class="batch-item-meta"><span>${sizeText}</span><span>${item.typeLabel || ''}</span><span>${exifBadge}</span></span>
      <span class="batch-item-mode">${modeLabel} · ${layoutLabel}</span>
    </button>`;
  }).join('');
}

function escapeHtml(text){
  return String(text ?? '').replace(/[&<>"']/g, ch => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[ch]));
}

async function loadPreviewImageFromItem(item){
  if(!item) return;
  return new Promise((resolve, reject) => {
    const nextImage = new Image();
    nextImage.onload = () => {
      image = nextImage;
      imageLoaded = true;
      currentFileName = item.name || 'image.jpg';
      $('thumb').src = item.url;
      $('fileName').textContent = currentFileName;
      $('imageSize').textContent = `${item.width || nextImage.naturalWidth} × ${item.height || nextImage.naturalHeight}`;
      originalExifValues = item.originalExifValues || null;
      updateExifSummary();
      renderPreview();
      $('statusText').textContent = '준비됨';
      resolve();
    };
    nextImage.onerror = () => reject(new Error('이미지를 불러오지 못했습니다.'));
    nextImage.src = item.url;
  });
}

async function selectPhotoById(id, {preserveCurrent=true} = {}){
  const nextItem = photoItems.find(item => item.id === id);
  if(!nextItem) return;
  if(preserveCurrent) syncCurrentPhotoValues();
  selectedPhotoId = id;

  if(!batchApplyMode){
    if(!nextItem.designState) nextItem.designState = clonePlain(captureDesignState());
    applyDesignState(nextItem.designState, {render:false, save:false});
    await ensureSelectedUserFonts({render:false, silent:true});
  }

  applyPhotoFieldValues({textValues: nextItem.textValues, exifValues: nextItem.exifValues}, {render:false, save:false});
  await loadPreviewImageFromItem(nextItem);
  renderBatchList();
}

function buildStateForPhoto(baseState, item){
  let state = clonePlain(baseState);
  if(!batchApplyMode && item.designState){
    const design = clonePlain(item.designState);
    Object.assign(state, design);
    state.layout = design.layout === 'polaroid' ? 'brush' : (design.layout || state.layout);
    state.elementLayoutState = clonePlain(design.elementLayoutState || {});
  }
  Object.assign(state, item.textValues || {}, item.exifValues || {});
  return state;
}

async function measureImageSource(url){
  return new Promise((resolve, reject) => {
    const probe = new Image();
    probe.onload = () => resolve({width: probe.naturalWidth, height: probe.naturalHeight});
    probe.onerror = () => reject(new Error('이미지 크기를 읽지 못했습니다.'));
    probe.src = url;
  });
}

function isHeicFile(file){
  return /\.(heic|heif)$/i.test(file?.name || '') || /image\/(heic|heif)/i.test(file?.type || '');
}

function exifReaderValue(tags, ...names){
  for(const name of names){
    const tag = tags && tags[name];
    if(!tag) continue;
    const value = tag.value ?? tag.description;
    if(Array.isArray(value)) return value.length === 1 ? value[0] : value;
    if(value !== undefined && value !== null && value !== '') return value;
  }
  return '';
}

function normalizeExifText(value){
  if(value === undefined || value === null) return '';
  if(Array.isArray(value)) return value.map(normalizeExifText).filter(Boolean).join(', ');
  return String(value).replace(/\0/g, '').trim();
}

function formatIsoText(value){
  const raw = normalizeExifText(value);
  if(!raw) return '';
  const cleaned = raw.replace(/^ISO[\s:_-]*/i, '').trim();
  return cleaned ? `ISO ${cleaned}` : '';
}

function formatLensInfoValue(value){
  if(value === undefined || value === null || value === '') return '';
  if(Array.isArray(value)){
    const numbers = value.map(item => Number(item)).filter(Number.isFinite);
    if(numbers.length >= 4){
      const [minFocal,maxFocal,minAperture,maxAperture] = numbers;
      const focalText = Math.abs(minFocal - maxFocal) < 0.05
        ? `${Math.round(minFocal * 10) / 10}mm`
        : `${Math.round(minFocal * 10) / 10}–${Math.round(maxFocal * 10) / 10}mm`;
      const apertureText = Math.abs(minAperture - maxAperture) < 0.05
        ? `F${Math.round(minAperture * 10) / 10}`
        : `F${Math.round(minAperture * 10) / 10}–F${Math.round(maxAperture * 10) / 10}`;
      return `${focalText} ${apertureText}`;
    }
    return numbers.length ? numbers.join(' / ') : normalizeExifText(value);
  }
  return normalizeExifText(value);
}

function combineLensParts(...parts){
  const result = [];
  const normalized = [];
  parts.flat().forEach(part => {
    const value = normalizeExifText(part);
    if(!value) return;
    const key = value.toLowerCase().replace(/[^a-z0-9가-힣]+/g, '');
    if(!key) return;
    if(normalized.some(existing => existing === key || existing.includes(key) || key.includes(existing))) return;
    normalized.push(key);
    result.push(value);
  });
  return result.join(' · ');
}

function exifReaderText(tags, ...names){
  for(const name of names){
    const tag = tags && tags[name];
    if(!tag) continue;
    const value = tag.description ?? tag.value;
    const text = normalizeExifText(value);
    if(text) return text;
  }
  return '';
}

function normalizeExifReaderTags(tags){
  const rational = value => {
    if(typeof value === 'number') return value;
    if(Array.isArray(value) && value.length >= 2 && Number(value[1])) return Number(value[0]) / Number(value[1]);
    const n = Number(value);
    return Number.isFinite(n) ? n : 0;
  };
  const lensModel = exifReaderText(tags, 'LensModel');
  const lensName = exifReaderText(tags, 'Lens');
  return {
    make: exifReaderValue(tags, 'Make'),
    model: exifReaderValue(tags, 'Model'),
    lens: lensModel || lensName,
    focal: rational(exifReaderValue(tags, 'FocalLength')),
    aperture: rational(exifReaderValue(tags, 'FNumber', 'ApertureValue')),
    exposure: rational(exifReaderValue(tags, 'ExposureTime')),
    iso: exifReaderValue(tags, 'ISOSpeedRatings', 'PhotographicSensitivity', 'ISO'),
    datetime: exifReaderValue(tags, 'DateTimeOriginal', 'DateTimeDigitized', 'DateTime')
  };
}

async function readExifFromFile(file){
  try{
    if(typeof ExifReader !== 'undefined'){
      const tags = await ExifReader.load(file, {expanded:false});
      return normalizeExifReaderTags(tags || {});
    }
  }catch(error){
    console.warn('ExifReader parse failed:', error);
  }
  if(file.type === 'image/jpeg' || /\.jpe?g$/i.test(file.name || '')){
    try{return parseExif(await file.arrayBuffer()) || {};}catch(error){console.warn('EXIF parse failed:', error);}
  }
  return {};
}

async function createDisplaySourceForFile(file){
  if(!isHeicFile(file)) return {url:URL.createObjectURL(file), convertedBlob:null};
  if(typeof heic2any === 'undefined') throw new Error('HEIC 변환 모듈을 불러오지 못했습니다. 인터넷 연결 또는 파일 구성을 확인하세요.');
  const converted = await heic2any({blob:file, toType:'image/jpeg', quality:0.94});
  const blob = Array.isArray(converted) ? converted[0] : converted;
  if(!(blob instanceof Blob)) throw new Error('HEIC 이미지를 JPEG로 변환하지 못했습니다.');
  return {url:URL.createObjectURL(blob), convertedBlob:blob};
}

async function createPhotoItemFromFile(file, baseTextValues, baseDesignState){
  const source = await createDisplaySourceForFile(file);
  const url = source.url;
  const dims = await measureImageSource(url);
  const parsedExif = await readExifFromFile(file);

  const exifValues = {};
  EXIF_FIELD_IDS.forEach(id => exifValues[id] = '');
  const previousImage = image;
  const previousLoaded = imageLoaded;
  const backupValues = captureExifValues();
  const blanks = {};
  EXIF_FIELD_IDS.forEach(id => blanks[id] = '');
  setExifValues(blanks, {render:false, save:false});
  applyExif(parsedExif);
  const captured = captureExifValues();
  Object.assign(exifValues, captured);
  setExifValues(backupValues, {render:false, save:false});
  image = previousImage;
  imageLoaded = previousLoaded;

  return {
    id: `photo_${++photoIdSeed}`,
    name: file.name,
    url,
    file,
    convertedBlob: source.convertedBlob,
    width: dims.width,
    height: dims.height,
    hasExif: !!Object.values(parsedExif || {}).filter(Boolean).length,
    originalExifValues: exifValues,
    exifValues: {...exifValues},
    textValues: {...baseTextValues},
    designState: clonePlain(baseDesignState),
    typeLabel: (file.type || '').replace('image/','').toUpperCase() || 'IMAGE'
  };
}

async function createPhotoItemFromUrl(name, url, baseTextValues, baseDesignState){
  const dims = await measureImageSource(url);
  return {
    id: `photo_${++photoIdSeed}`,
    name,
    url,
    file: null,
    width: dims.width,
    height: dims.height,
    hasExif: false,
    originalExifValues: null,
    exifValues: (() => { const blank = {}; EXIF_FIELD_IDS.forEach(id => blank[id] = ''); return blank; })(),
    textValues: {...baseTextValues},
    designState: clonePlain(baseDesignState),
    typeLabel: 'SAMPLE'
  };
}

async function loadFiles(fileList){
  const files = [...fileList].filter(file => /^image\//.test(file.type) || /\.(jpe?g|png|webp|heic|heif)$/i.test(file.name || ''));
  if(!files.length) return;
  $('statusText').textContent = `사진 ${files.length}장 읽는 중…`;
  const baseTextValues = captureTextValues();
  const baseDesignState = captureDesignState();
  const items = [];
  const failed = [];
  for(const file of files){
    try{
      items.push(await createPhotoItemFromFile(file, baseTextValues, baseDesignState));
    }catch(error){
      console.error(`Image load failed: ${file.name}`, error);
      failed.push(file.name);
    }
  }
  if(!items.length){
    $('statusText').textContent = '사진 불러오기 실패';
    alert(`선택한 사진을 불러오지 못했습니다.\n\n${failed.join('\n')}`);
    return;
  }
  photoItems = items;
  renderBatchList();
  await selectPhotoById(photoItems[0].id, {preserveCurrent:false});
  $('statusText').textContent = failed.length ? `사진 ${photoItems.length}장 준비됨 · ${failed.length}장 실패` : `사진 ${photoItems.length}장 준비됨`;
  if(failed.length) alert(`다음 파일은 불러오지 못했습니다.\n\n${failed.join('\n')}`);
}

function captureExifValues(){
    const values = {};
    EXIF_FIELD_IDS.forEach(id => {
      const element = $(id);
      values[id] = element ? element.value : '';
    });
    return values;
  }

  function setExifValues(values, {render=true, save=true} = {}){
    EXIF_FIELD_IDS.forEach(id => {
      const element = $(id);
      if(element) element.value = values && values[id] != null ? values[id] : '';
    });
    updateExifSummary();
    if(save) saveState();
    if(render) renderPreview();
  }

  function updateExifSummary(){
    const values = captureExifValues();
    const camera = [values.make, values.model].filter(Boolean).join(' · ');
    const exposure = [values.focal, values.aperture, values.shutter, values.iso].filter(Boolean).join('  ·  ');
    const dateTime = [values.date ? values.date.replaceAll('-', '.') : '', values.time].filter(Boolean).join('  ');

    const cameraEl = $('exifSummaryCamera');
    const lensEl = $('exifSummaryLens');
    const exposureEl = $('exifSummaryExposure');
    const dateEl = $('exifSummaryDate');

    if(cameraEl) cameraEl.textContent = camera || '카메라 정보 없음';
    if(lensEl) lensEl.textContent = values.lens || '렌즈 정보 없음';
    if(exposureEl) exposureEl.textContent = exposure || '노출 정보 없음';
    if(dateEl) dateEl.textContent = dateTime;
  }

  function restoreOriginalExif(){
    if(!originalExifValues){
      alert('현재 사진에서 읽어 둔 EXIF 정보가 없습니다.');
      return;
    }
    setExifValues(originalExifValues);
    $('statusText').textContent = '사진 EXIF 복원 완료';
  }

  function clearExifValues(){
    const confirmed = window.confirm('현재 입력된 EXIF 정보를 모두 비울까요?');
    if(!confirmed) return;
    const cleared = {};
    EXIF_FIELD_IDS.forEach(id => { cleared[id] = ''; });
    setExifValues(cleared);
    $('statusText').textContent = 'EXIF 정보 비움';
  }

  function dateText(state){
    return state.date ? state.date.replaceAll('-', '.') : '';
  }

  function exifLine(state){
    return [state.focal, state.aperture, state.shutter, formatIsoText(state.iso)].filter(Boolean).join('  ·  ');
  }

  function stampExifLine(state){
    return [state.focal, state.aperture, state.shutter, formatIsoText(state.iso)].filter(Boolean).join(' ').toUpperCase().replace(/MM/g,'MM');
  }

  function roundedRectPath(ctx, x,y,w,h,r){
    r = Math.min(r,w/2,h/2);
    ctx.beginPath();
    ctx.moveTo(x+r,y);
    ctx.arcTo(x+w,y,x+w,y+h,r);
    ctx.arcTo(x+w,y+h,x,y+h,r);
    ctx.arcTo(x,y+h,x,y,r);
    ctx.arcTo(x,y,x+w,y,r);
    ctx.closePath();
  }

  function drawPhoto(ctx, x, y, w, h, radius){
    ctx.save();
    roundedRectPath(ctx, x, y, w, h, radius);
    ctx.clip();
    if(imageLoaded){
      ctx.drawImage(image, x, y, w, h);
    }else{
      ctx.fillStyle = '#b7b7b7';
      ctx.fillRect(x,y,w,h);
    }
    ctx.restore();
  }


  const collageImageCache = new Map();

  function requestCollageImage(url){
    if(!url) return {status:'error', img:null};
    const cached = collageImageCache.get(url);
    if(cached) return cached;
    const img = new Image();
    const record = {status:'loading', img, src:url};
    img.onload = () => {
      record.status = 'loaded';
      try{ renderPreview(); }catch(_error){}
    };
    img.onerror = () => {
      record.status = 'error';
      try{ renderPreview(); }catch(_error){}
    };
    img.src = url;
    collageImageCache.set(url, record);
    return record;
  }

  function drawSourceCover(ctx, source, x, y, w, h, radius=0){
    ctx.save();
    roundedRectPath(ctx, x, y, w, h, radius);
    ctx.clip();
    if(source && source.naturalWidth && source.naturalHeight){
      const scale = Math.max(w / source.naturalWidth, h / source.naturalHeight);
      const drawW = source.naturalWidth * scale;
      const drawH = source.naturalHeight * scale;
      const dx = x + (w - drawW) / 2;
      const dy = y + (h - drawH) / 2;
      ctx.drawImage(source, dx, dy, drawW, drawH);
    }else{
      ctx.fillStyle = '#d0d0d0';
      ctx.fillRect(x, y, w, h);
    }
    ctx.restore();
  }

  function getMultiFrameCount(layoutName){
    if(layoutName === 'diptych' || layoutName === 'double_stack') return 2;
    return 3;
  }

  function getOrderedMultiFrameItems(requiredCount=3){
    const selected = getSelectedPhotoItem();
    const ordered = [];
    if(selected) ordered.push(selected);
    photoItems.forEach(item => {
      if(!item) return;
      if(selected && item.id === selected.id) return;
      ordered.push(item);
    });
    if(!ordered.length && imageLoaded){
      ordered.push({id:'current', url:image.src || image.currentSrc || '', width:image.naturalWidth, height:image.naturalHeight, name:currentFileName || 'image.jpg'});
    }
    return ordered.slice(0, requiredCount);
  }

  function getMultiFrameRatio(item, fallback=1.5){
    const w = Number(item && item.width) || 0;
    const h = Number(item && item.height) || 0;
    if(w > 0 && h > 0) return w / h;
    return fallback;
  }

  function drawSourceContain(ctx, source, x, y, w, h){
    if(source && source.naturalWidth && source.naturalHeight){
      const scale = Math.min(w / source.naturalWidth, h / source.naturalHeight);
      const drawW = source.naturalWidth * scale;
      const drawH = source.naturalHeight * scale;
      const dx = x + (w - drawW) / 2;
      const dy = y + (h - drawH) / 2;
      ctx.drawImage(source, dx, dy, drawW, drawH);
      return {x:dx, y:dy, w:drawW, h:drawH};
    }
    ctx.fillStyle = '#dedbd5';
    ctx.fillRect(x, y, w, h);
    return {x,y,w,h};
  }

  function drawMultiFramePlaceholder(ctx, x, y, w, h, index, fonts){
    ctx.fillStyle = '#dedbd5';
    ctx.fillRect(x, y, w, h);
    ctx.strokeStyle = 'rgba(0,0,0,0.08)';
    ctx.strokeRect(x + 0.5, y + 0.5, Math.max(0, w - 1), Math.max(0, h - 1));
    ctx.fillStyle = '#8a867f';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = `600 ${Math.max(16, Math.min(28, Math.min(w,h) * 0.12))}px ${fonts.meta}`;
    ctx.fillText(`PHOTO ${index + 1}`, x + w / 2, y + h / 2);
  }

  function getMultiFrameGeometry(layoutName, items, gap){
    const variant = layoutName || 'hero_two_landscape';
    if(variant === 'hero_two_portrait'){
      const height = 1000;
      const heroRatio = getMultiFrameRatio(items[0], 2/3);
      const miniRatio1 = getMultiFrameRatio(items[1], 3/2);
      const miniRatio2 = getMultiFrameRatio(items[2], 3/2);
      const heroW = height * heroRatio;
      const miniW = Math.max(1, (height - gap) / ((1 / miniRatio1) + (1 / miniRatio2)));
      const miniH1 = miniW / miniRatio1;
      const miniH2 = miniW / miniRatio2;
      const width = heroW + gap + miniW;
      return {
        innerW: width,
        innerH: height,
        slots:[
          {x:0, y:0, w:heroW, h:height},
          {x:heroW + gap, y:0, w:miniW, h:miniH1},
          {x:heroW + gap, y:miniH1 + gap, w:miniW, h:miniH2}
        ]
      };
    }
    if(variant === 'triple_strip'){
      const width = 1000;
      const h1 = width / getMultiFrameRatio(items[0], 3);
      const h2 = width / getMultiFrameRatio(items[1], 3);
      const h3 = width / getMultiFrameRatio(items[2], 3);
      const height = h1 + h2 + h3 + gap * 2;
      return {
        innerW: width,
        innerH: height,
        slots:[
          {x:0, y:0, w:width, h:h1},
          {x:0, y:h1 + gap, w:width, h:h2},
          {x:0, y:h1 + gap + h2 + gap, w:width, h:h3}
        ]
      };
    }
    if(variant === 'double_stack'){
      const width = 1000;
      const h1 = width / getMultiFrameRatio(items[0], 1.5);
      const h2 = width / getMultiFrameRatio(items[1], 1.5);
      const height = h1 + h2 + gap;
      return {
        innerW: width,
        innerH: height,
        slots:[
          {x:0, y:0, w:width, h:h1},
          {x:0, y:h1 + gap, w:width, h:h2}
        ]
      };
    }
    if(variant === 'diptych'){
      const height = 1000;
      const w1 = height * getMultiFrameRatio(items[0], 2/3);
      const w2 = height * getMultiFrameRatio(items[1], 2/3);
      const width = w1 + w2 + gap;
      return {
        innerW: width,
        innerH: height,
        slots:[
          {x:0, y:0, w:w1, h:height},
          {x:w1 + gap, y:0, w:w2, h:height}
        ]
      };
    }
    const width = 1000;
    const topH = width / getMultiFrameRatio(items[0], 1.5);
    const miniW = (width - gap) / 2;
    const miniH1 = miniW / getMultiFrameRatio(items[1], 1.5);
    const miniH2 = miniW / getMultiFrameRatio(items[2], 1.5);
    const bottomRowH = Math.max(miniH1, miniH2);
    const height = topH + gap + bottomRowH;
    return {
      innerW: width,
      innerH: height,
      slots:[
        {x:0, y:0, w:width, h:topH},
        {x:0, y:topH + gap, w:miniW, h:bottomRowH},
        {x:miniW + gap, y:topH + gap, w:miniW, h:bottomRowH}
      ]
    };
  }

  const brushMaskCache = new Map();

  const BRUSH_ASSET_BASE_PATH = 'assets/brush_photo_edge';
  const brushAssetCache = new Map();

  function getBrushAspectKey(width, height){
    const ratio = Math.max(1, width) / Math.max(1, height);
    if(ratio > 1.08) return 'landscape';
    if(ratio < 0.92) return 'portrait';
    return 'square';
  }

  function getBrushAssetPath(style, aspectKey, kind){
    return `${BRUSH_ASSET_BASE_PATH}/${String(style || 'A').toUpperCase()}_${aspectKey}_${kind}.png`;
  }

  function loadBrushAsset(style, aspectKey, kind){
    const normalizedStyle = String(style || 'A').toUpperCase();
    const cacheKey = `${normalizedStyle}:${aspectKey}:${kind}`;
    const cached = brushAssetCache.get(cacheKey);
    if(cached) return cached;

    const img = new Image();
    const record = { status:'loading', img, src:getBrushAssetPath(normalizedStyle, aspectKey, kind) };
    img.onload = () => {
      record.status = 'loaded';
      try{ renderPreview(); }catch(_error){}
    };
    img.onerror = () => {
      record.status = 'error';
    };
    img.src = record.src;
    brushAssetCache.set(cacheKey, record);
    return record;
  }

  function getBrushAsset(style, width, height, kind){
    const aspectKey = getBrushAspectKey(width, height);
    const record = loadBrushAsset(style, aspectKey, kind);
    if(record && record.status === 'loaded' && record.img && record.img.naturalWidth > 0){
      return record.img;
    }
    return null;
  }

  const BRUSH_MASK_DATA_URLS = {
    A:'data:image/png;base64,',
    B:'data:image/png;base64,',
    C:'data:image/png;base64,',
    D:'data:image/png;base64,',
    E:'data:image/png;base64,',
    F:'data:image/png;base64,'
  };
  const brushMaskImages = new Map();

  function preloadBrushMaskImages(){
    Object.entries(BRUSH_MASK_DATA_URLS).forEach(([style, src]) => {
      const maskImage = new Image();
      maskImage.onload = () => {
        for(const key of Array.from(brushMaskCache.keys())){
          if(String(key).startsWith(`cutout:${style}:`)) brushMaskCache.delete(key);
        }
        try{ renderPreview(); }catch(_err){}
      };
      maskImage.src = src;
      brushMaskImages.set(style, maskImage);
    });
  }
  preloadBrushMaskImages();


  function brushHash1(value, seed){
    let n = (Math.floor(value) ^ Math.imul(seed | 0, 374761393)) | 0;
    n = Math.imul(n ^ (n >>> 13), 1274126177);
    n = (n ^ (n >>> 16)) >>> 0;
    return n / 4294967295;
  }

  function brushHash2(x, y, seed){
    let n = (Math.imul(x | 0, 374761393) + Math.imul(y | 0, 668265263) + Math.imul(seed | 0, 69069)) | 0;
    n = Math.imul(n ^ (n >>> 13), 1274126177);
    n = (n ^ (n >>> 16)) >>> 0;
    return n / 4294967295;
  }

  function brushSmoothNoise(value, seed){
    const base = Math.floor(value);
    const fraction = value - base;
    const smooth = fraction * fraction * (3 - 2 * fraction);
    const a = brushHash1(base, seed);
    const b = brushHash1(base + 1, seed);
    return a + (b - a) * smooth;
  }

  function clamp01(value){
    return Math.max(0, Math.min(1, value));
  }

  function smoothStep(edge0, edge1, value){
    if(edge0 === edge1) return value < edge0 ? 0 : 1;
    const t = clamp01((value - edge0) / (edge1 - edge0));
    return t * t * (3 - 2 * t);
  }

  function brushStyleParameters(style){
    const styles = {
      A:{seed:11,inset:10,amplitude:22,scale:48,feather:1.4,band:44,dry:0.70,grain:0.18},
      B:{seed:23,inset:15,amplitude:26,scale:92,feather:3.0,band:28,dry:0.14,grain:0.05},
      C:{seed:37,inset:9,amplitude:34,scale:38,feather:0.9,band:36,dry:0.42,grain:0.15},
      D:{seed:51,inset:24,amplitude:27,scale:110,feather:18,band:58,dry:0.18,grain:0.10},
      E:{seed:67,inset:17,amplitude:23,scale:74,feather:2.4,band:32,dry:0.12,grain:0.04,blocky:true},
      F:{seed:83,inset:19,amplitude:23,scale:68,feather:10,band:54,dry:0.40,grain:0.14}
    };
    return styles[String(style || 'A').toUpperCase()] || styles.A;
  }

  function brushEdgeThreshold(position, length, params, seedOffset){
    const scale = Math.max(12, params.scale);
    let noiseValue;
    if(params.blocky){
      const block = Math.floor(position / Math.max(18, scale * 0.42));
      noiseValue = brushHash1(block, params.seed + seedOffset);
      const secondary = brushHash1(Math.floor(position / 9), params.seed + seedOffset + 91);
      noiseValue = noiseValue * 0.78 + secondary * 0.22;
    }else{
      const broad = brushSmoothNoise(position / scale, params.seed + seedOffset);
      const fine = brushSmoothNoise(position / Math.max(8, scale * 0.24), params.seed + seedOffset + 41);
      noiseValue = broad * 0.74 + fine * 0.26;
    }
    const endTaper = Math.sin(Math.PI * clamp01(position / Math.max(1, length)));
    const cornerLift = (1 - endTaper) * params.amplitude * 0.35;
    return params.inset + (noiseValue - 0.5) * params.amplitude * 2 + cornerLift;
  }

  function createProceduralBrushMask(width, height, style){
    const normalizedStyle = String(style || 'A').toUpperCase();
    const key = `${normalizedStyle}:${width}x${height}`;
    if(brushMaskCache.has(key)) return brushMaskCache.get(key);

    const params = brushStyleParameters(normalizedStyle);
    const canvas = document.createElement('canvas');
    canvas.width = Math.max(1, Math.round(width));
    canvas.height = Math.max(1, Math.round(height));
    const ctx = canvas.getContext('2d');
    const imageData = ctx.createImageData(canvas.width, canvas.height);
    const data = imageData.data;

    const topEdges = new Float32Array(canvas.width);
    const bottomEdges = new Float32Array(canvas.width);
    for(let x = 0; x < canvas.width; x++){
      topEdges[x] = brushEdgeThreshold(x, canvas.width, params, 13);
      bottomEdges[x] = brushEdgeThreshold(x, canvas.width, params, 19);
    }
    const leftEdges = new Float32Array(canvas.height);
    const rightEdges = new Float32Array(canvas.height);
    for(let y = 0; y < canvas.height; y++){
      leftEdges[y] = brushEdgeThreshold(y, canvas.height, params, 3);
      rightEdges[y] = brushEdgeThreshold(y, canvas.height, params, 7);
    }

    for(let y = 0; y < canvas.height; y++){
      const leftEdge = leftEdges[y];
      const rightEdge = rightEdges[y];
      for(let x = 0; x < canvas.width; x++){
        const distances = [
          y - topEdges[x],
          canvas.height - 1 - y - bottomEdges[x],
          x - leftEdge,
          canvas.width - 1 - x - rightEdge
        ];
        let nearestIndex = 0;
        let distance = distances[0];
        for(let i = 1; i < 4; i++){
          if(distances[i] < distance){
            distance = distances[i];
            nearestIndex = i;
          }
        }

        let alpha = smoothStep(-params.feather, Math.max(1, params.feather), distance);
        const nearEdge = clamp01(1 - Math.max(0, distance) / params.band);

        if(alpha > 0 && nearEdge > 0){
          const along = nearestIndex < 2 ? x : y;
          const cross = nearestIndex < 2 ? y : x;
          const bristleWidth = normalizedStyle === 'A' ? 3 : (normalizedStyle === 'C' ? 5 : 7);
          const bristle = brushHash1(Math.floor(along / bristleWidth), params.seed + nearestIndex * 17);
          const strokeWave = brushSmoothNoise(along / 22, params.seed + nearestIndex * 29 + 101);
          const grain = brushHash2(Math.floor(along / 4), Math.floor(cross / 5), params.seed + nearestIndex * 11);
          const dryThreshold = params.dry * nearEdge * (0.54 + strokeWave * 0.64);
          if(bristle < dryThreshold){
            const residue = 0.08 + grain * 0.42 + (1 - nearEdge) * 0.48;
            alpha *= clamp01(residue);
          }
          if(grain < params.grain * nearEdge){
            alpha *= 0.22 + grain * 1.8;
          }
        }

        const index = (y * canvas.width + x) * 4;
        data[index] = 255;
        data[index + 1] = 255;
        data[index + 2] = 255;
        data[index + 3] = Math.round(clamp01(alpha) * 255);
      }
    }

    ctx.putImageData(imageData, 0, 0);

    const random = (() => {
      let seed = params.seed * 9973;
      return () => {
        seed = (seed * 1664525 + 1013904223) >>> 0;
        return seed / 4294967296;
      };
    })();

    if(normalizedStyle === 'B' || normalizedStyle === 'E'){
      ctx.save();
      ctx.fillStyle = 'rgba(255,255,255,.82)';
      const count = normalizedStyle === 'E' ? 58 : 34;
      for(let i = 0; i < count; i++){
        const horizontal = random() > 0.5;
        const side = Math.floor(random() * 4);
        const length = 18 + random() * (normalizedStyle === 'E' ? 84 : 54);
        const thickness = 4 + random() * (normalizedStyle === 'E' ? 24 : 18);
        let x = random() * canvas.width;
        let y = random() * canvas.height;
        if(side === 0) y = random() * 28;
        if(side === 1) x = canvas.width - random() * 28;
        if(side === 2) y = canvas.height - random() * 28;
        if(side === 3) x = random() * 28;
        ctx.globalAlpha = 0.32 + random() * 0.55;
        if(horizontal) ctx.fillRect(x - length / 2, y - thickness / 2, length, thickness);
        else ctx.fillRect(x - thickness / 2, y - length / 2, thickness, length);
      }
      ctx.restore();
    }

    if(normalizedStyle === 'C'){
      ctx.save();
      ctx.fillStyle = '#fff';
      for(let i = 0; i < 72; i++){
        const side = Math.floor(random() * 4);
        const radius = 0.8 + random() * 4.8;
        let x = random() * canvas.width;
        let y = random() * canvas.height;
        if(side === 0) y = random() * 22;
        if(side === 1) x = canvas.width - random() * 22;
        if(side === 2) y = canvas.height - random() * 22;
        if(side === 3) x = random() * 22;
        ctx.globalAlpha = 0.25 + random() * 0.75;
        ctx.beginPath();
        ctx.arc(x, y, radius, 0, Math.PI * 2);
        ctx.fill();
      }
      ctx.restore();
    }

    brushMaskCache.set(key, canvas);
    if(brushMaskCache.size > 8){
      const oldestKey = brushMaskCache.keys().next().value;
      brushMaskCache.delete(oldestKey);
    }
    return canvas;
  }

  function createBrushMask(width, height, style){
    const normalizedStyle = String(style || 'A').toUpperCase();
    const key = `cutout:${normalizedStyle}:${width}x${height}`;
    if(brushMaskCache.has(key)) return brushMaskCache.get(key);

    const source = brushMaskImages.get(normalizedStyle);
    if(source && source.complete && source.naturalWidth > 0){
      const maskCanvas = document.createElement('canvas');
      maskCanvas.width = Math.max(1, Math.round(width));
      maskCanvas.height = Math.max(1, Math.round(height));
      const maskCtx = maskCanvas.getContext('2d');
      maskCtx.imageSmoothingEnabled = true;
      maskCtx.imageSmoothingQuality = 'high';
      maskCtx.clearRect(0, 0, maskCanvas.width, maskCanvas.height);
      maskCtx.drawImage(source, 0, 0, maskCanvas.width, maskCanvas.height);
      brushMaskCache.set(key, maskCanvas);
      if(brushMaskCache.size > 20){
        const oldestKey = brushMaskCache.keys().next().value;
        brushMaskCache.delete(oldestKey);
      }
      return maskCanvas;
    }

    // Data URLs normally load immediately. This fallback keeps first-render behavior stable.
    return createProceduralBrushMask(width, height, normalizedStyle);
  }


  function drawBrushPhoto(ctx, x, y, w, h, style){
    const temp = document.createElement('canvas');
    temp.width = Math.max(1, Math.round(w));
    temp.height = Math.max(1, Math.round(h));
    const tctx = temp.getContext('2d');
    if(imageLoaded){
      tctx.drawImage(image, 0, 0, temp.width, temp.height);
    }else{
      tctx.fillStyle = '#b7b7b7';
      tctx.fillRect(0, 0, temp.width, temp.height);
    }

    const assetMask = getBrushAsset(style, temp.width, temp.height, 'mask');
    tctx.globalCompositeOperation = 'destination-in';
    if(assetMask){
      tctx.drawImage(assetMask, 0, 0, temp.width, temp.height);
    }else{
      tctx.drawImage(createBrushMask(temp.width, temp.height, style), 0, 0);
    }
    tctx.globalCompositeOperation = 'source-over';

    const assetOverlay = getBrushAsset(style, temp.width, temp.height, 'overlay');
    if(assetOverlay){
      tctx.drawImage(assetOverlay, 0, 0, temp.width, temp.height);
    }

    ctx.drawImage(temp, x, y, w, h);
  }

  function setFont(ctx, size, weight, family, italic=false){
    ctx.font = `${italic ? 'italic ' : ''}${weight} ${size}px ${family}`;
  }

  function drawText(ctx, str, x, y, size=28, color='#111', weight='400', family='Arial', align='left', italic=false){
    ctx.save();
    ctx.fillStyle = color;
    ctx.textAlign = align;
    ctx.textBaseline = 'alphabetic';
    setFont(ctx, size, weight, family, italic);
    ctx.fillText(String(str || ''), x, y);
    ctx.restore();
  }

  function drawFittedText(ctx, str, x, y, maxWidth, size, minSize, color='#111', weight='400', family='Arial', align='left'){
    const value = String(str || '');
    let finalSize = size;

    ctx.save();
    ctx.textBaseline = 'alphabetic';
    ctx.textAlign = align;
    ctx.fillStyle = color;

    setFont(ctx, finalSize, weight, family);
    while(finalSize > minSize && ctx.measureText(value).width > maxWidth){
      finalSize -= 0.5;
      setFont(ctx, finalSize, weight, family);
    }

    let output = value;
    if(ctx.measureText(output).width > maxWidth){
      const ellipsis = '…';
      while(output.length > 1 && ctx.measureText(output + ellipsis).width > maxWidth){
        output = output.slice(0, -1);
      }
      output += ellipsis;
    }

    const clipX = align === 'right' ? x - maxWidth : x;
    ctx.beginPath();
    ctx.rect(clipX, y - finalSize * 1.15, maxWidth, finalSize * 1.45);
    ctx.clip();
    ctx.fillText(output, x, y);
    ctx.restore();

    return finalSize;
  }

  function wrapLines(ctx, str, maxWidth, size, family, weight='400', maxLines=6){
    setFont(ctx, size, weight, family);
    const lines = [];
    const paras = String(str || '').split('\n');
    paras.forEach((para, pIdx) => {
      const text = para || '';
      if(text.trim() === ''){
        if(lines.length < maxLines) lines.push('');
        return;
      }
      let line = '';
      for(const ch of text){
        const test = line + ch;
        if(ctx.measureText(test).width > maxWidth && line){
          lines.push(line);
          line = ch;
          if(lines.length >= maxLines) break;
        }else{
          line = test;
        }
      }
      if(lines.length < maxLines && line) lines.push(line);
      // Explicit newline already starts the next paragraph on the next line.
    });
    return lines.slice(0, maxLines);
  }

  function drawWrappedText(ctx, str, x, y, maxWidth, lineHeight, size, color, family, weight='400', maxLines=6, align='left'){
    ctx.save();
    ctx.fillStyle = color;
    ctx.textAlign = align;
    ctx.textBaseline = 'top';
    setFont(ctx, size, weight, family);
    const lines = wrapLines(ctx, str, maxWidth, size, family, weight, maxLines);
    lines.forEach((line, i) => ctx.fillText(line, x, y + i * lineHeight));
    ctx.restore();
    return lines.length * lineHeight;
  }

  function wrapLinesComplete(ctx, str, maxWidth, size, family, weight='400'){
    setFont(ctx, size, weight, family);
    const lines = [];
    const paragraphs = String(str || '').split('\n');

    paragraphs.forEach((paragraph, paragraphIndex) => {
      if(paragraph === ''){
        lines.push('');
        return;
      }

      let lineText = '';
      for(const character of paragraph){
        const test = lineText + character;
        if(lineText && ctx.measureText(test).width > maxWidth){
          lines.push(lineText);
          lineText = character;
        }else{
          lineText = test;
        }
      }

      if(lineText) lines.push(lineText);
      // Explicit newline already creates the next line without an extra blank row.
    });

    return lines;
  }

  function fitWrappedText(ctx, str, maxWidth, maxLines, startSize, minSize, family, weight='700'){
    let size = startSize;
    let completeLines = [];

    while(size >= minSize){
      completeLines = wrapLinesComplete(ctx, str, maxWidth, size, family, weight);
      if(completeLines.length <= maxLines) break;
      size -= 2;
    }

    size = Math.max(minSize, size);
    completeLines = wrapLinesComplete(ctx, str, maxWidth, size, family, weight);

    const clipped = completeLines.length > maxLines;
    const lines = completeLines.slice(0, maxLines);

    if(clipped && lines.length){
      setFont(ctx, size, weight, family);
      const ellipsis = '…';
      let last = lines[lines.length - 1];

      while(last.length > 1 && ctx.measureText(last + ellipsis).width > maxWidth){
        last = last.slice(0, -1);
      }
      lines[lines.length - 1] = last + ellipsis;
    }

    return {
      size,
      lineHeight: Math.round(size * 1.08),
      lines
    };
  }

  function drawFittedWrappedText(ctx, str, x, y, maxWidth, maxLines, startSize, minSize, color, family, weight='700', align='left'){
    const fitted = fitWrappedText(
      ctx,
      str,
      maxWidth,
      maxLines,
      startSize,
      minSize,
      family,
      weight
    );

    ctx.save();
    ctx.fillStyle = color;
    ctx.textAlign = align;
    ctx.textBaseline = 'top';
    setFont(ctx, fitted.size, weight, family);

    fitted.lines.forEach((lineText, index) => {
      ctx.fillText(lineText, x, y + index * fitted.lineHeight);
    });

    ctx.restore();

    return {
      ...fitted,
      height: fitted.lines.length * fitted.lineHeight
    };
  }

  function line(ctx, x1,y1,x2,y2,color='#bbb',width=1){
    ctx.save();
    ctx.strokeStyle = color;
    ctx.lineWidth = width;
    ctx.beginPath();
    ctx.moveTo(x1,y1);
    ctx.lineTo(x2,y2);
    ctx.stroke();
    ctx.restore();
  }

  function fillGradientRect(ctx, x, y, w, h, direction='vertical', stops=[]){
    const grad = direction === 'horizontal'
      ? ctx.createLinearGradient(x, y, x + w, y)
      : ctx.createLinearGradient(x, y, x, y + h);
    stops.forEach(([offset, color]) => grad.addColorStop(offset, color));
    ctx.save();
    ctx.fillStyle = grad;
    ctx.fillRect(x, y, w, h);
    ctx.restore();
  }

  function hexToRgb(hex){
    const normalized = String(hex || '').trim();
    const match = normalized.match(/^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i);
    if(!match) return null;
    return {
      r: parseInt(match[1], 16),
      g: parseInt(match[2], 16),
      b: parseInt(match[3], 16)
    };
  }

  function frameShadowStrength(frameColor){
    const rgb = hexToRgb(frameColor);
    if(!rgb) return 0.06;
    const luminance = (0.2126 * rgb.r + 0.7152 * rgb.g + 0.0722 * rgb.b) / 255;
    if(luminance > 0.92) return 0.13;
    if(luminance > 0.82) return 0.10;
    if(luminance > 0.68) return 0.07;
    return 0.0;
  }

  function drawFrameEdgeShadow(ctx, x, y, w, h, frameColor){
    let alpha = frameShadowStrength(frameColor);
    if(alpha <= 0) return;

    /*
      A real shadow outside the JPEG canvas would require adding extra outer
      pixels. Instead, create a clearly visible but soft inset halo along the
      exact frame boundary. Concentric full-frame outlines keep all four sides
      and all four corners continuous, so no rectangular corner blocks appear.
    */
    alpha = Math.min(0.22, alpha * 1.42);
    const depth = Math.max(12, Math.min(24, Math.round(Math.min(w, h) * 0.024)));

    ctx.save();
    ctx.lineJoin = 'miter';
    ctx.lineCap = 'butt';

    for(let i = 0; i < depth; i++){
      const inset = i + 0.5;
      const progress = i / Math.max(1, depth - 1);
      const opacity = alpha * Math.pow(1 - progress, 2.15);
      const sw = w - inset * 2;
      const sh = h - inset * 2;
      if(sw <= 0 || sh <= 0) break;

      ctx.strokeStyle = `rgba(0,0,0,${opacity})`;
      ctx.lineWidth = 1;
      ctx.strokeRect(x + inset, y + inset, sw, sh);
    }

    /* A thin boundary line anchors very light frames on white pages. */
    ctx.strokeStyle = `rgba(0,0,0,${Math.min(0.16, alpha * 0.72)})`;
    ctx.lineWidth = 1;
    ctx.strokeRect(x + 0.5, y + 0.5, Math.max(1, w - 1), Math.max(1, h - 1));
    ctx.restore();
  }

  function drawFrameSurface(ctx, x, y, w, h, color){
    ctx.fillStyle = color;
    ctx.fillRect(x, y, w, h);
    drawFrameEdgeShadow(ctx, x, y, w, h, color);
  }

  function getTextAdjustments(state, kind, fallbackColor){
    const scaleRaw = Number(state[`${kind}Scale`] || 100);
    const dx = Number(state[`${kind}OffsetX`] || 0);
    const dy = Number(state[`${kind}OffsetY`] || 0);
    const scale = Math.max(0.6, Math.min(1.8, scaleRaw / 100));
    const color = state.textColorMode === 'custom'
      ? (state[`${kind}Color`] || fallbackColor)
      : fallbackColor;
    return {scale, dx, dy, color};
  }

  function getElementAdjustments(state, kind, elementKey, fallbackColor){
    const base = getTextAdjustments(state, kind, fallbackColor);
    const element = elementPlacementFromState(state, elementKey || kind);
    const elementScale = Math.max(0.6, Math.min(1.8, Number(element.scale || 100) / 100));
    return {
      scale:base.scale * elementScale,
      dx:base.dx + Number(element.x || 0),
      dy:base.dy + Number(element.y || 0),
      lineHeightScale:Math.max(0.7, Math.min(2.0, Number(element.lineHeight || 100) / 100)),
      color:base.color
    };
  }

  function applyInputTextShadow(ctx){
    ctx.shadowColor = 'rgba(0,0,0,0.16)';
    ctx.shadowBlur = 2;
    ctx.shadowOffsetX = 1;
    ctx.shadowOffsetY = 1;
  }

  function drawManagedText(ctx, state, kind, str, x, y, size=28, color='#111', weight='400', family='Arial', align='left', italic=false, elementKey=kind){
    const adj = getElementAdjustments(state, kind, elementKey, color);
    ctx.save();
    ctx.fillStyle = adj.color;
    ctx.textAlign = align;
    ctx.textBaseline = 'alphabetic';
    applyInputTextShadow(ctx);
    setFont(ctx, size * adj.scale, weight, family, italic);
    ctx.fillText(String(str || ''), x + adj.dx, y + adj.dy);
    ctx.restore();
  }

  function drawManagedFittedText(ctx, state, kind, str, x, y, maxWidth, size, minSize, color='#111', weight='400', family='Arial', align='left', elementKey=kind){
    const value = String(str || '');
    const adj = getElementAdjustments(state, kind, elementKey, color);
    let finalSize = size * adj.scale;
    const finalMin = Math.max(8, minSize * Math.min(adj.scale, 1.35));
    const drawX = x + adj.dx;
    const drawY = y + adj.dy;

    ctx.save();
    ctx.textBaseline = 'alphabetic';
    ctx.textAlign = align;
    ctx.fillStyle = adj.color;
    applyInputTextShadow(ctx);

    setFont(ctx, finalSize, weight, family);
    while(finalSize > finalMin && ctx.measureText(value).width > maxWidth){
      finalSize -= 0.5;
      setFont(ctx, finalSize, weight, family);
    }

    let output = value;
    if(ctx.measureText(output).width > maxWidth){
      const ellipsis = '…';
      while(output.length > 1 && ctx.measureText(output + ellipsis).width > maxWidth){
        output = output.slice(0, -1);
      }
      output += ellipsis;
    }

    const clipX = align === 'right' ? drawX - maxWidth : drawX;
    ctx.beginPath();
    ctx.rect(clipX, drawY - finalSize * 1.15, maxWidth, finalSize * 1.45);
    ctx.clip();
    ctx.fillText(output, drawX, drawY);
    ctx.restore();

    return finalSize;
  }

  function drawManagedWrappedText(ctx, state, kind, str, x, y, maxWidth, lineHeight, size, color, family, weight='400', maxLines=6, align='left', elementKey=kind){
    const adj = getElementAdjustments(state, kind, elementKey, color);
    const scaledSize = size * adj.scale;
    const scaledLineHeight = lineHeight * adj.scale * adj.lineHeightScale;
    ctx.save();
    ctx.fillStyle = adj.color;
    ctx.textAlign = align;
    ctx.textBaseline = 'top';
    applyInputTextShadow(ctx);
    setFont(ctx, scaledSize, weight, family);
    const lines = wrapLines(ctx, str, maxWidth, scaledSize, family, weight, maxLines);
    lines.forEach((line, i) => ctx.fillText(line, x + adj.dx, y + adj.dy + i * scaledLineHeight));
    ctx.restore();
    return lines.length * scaledLineHeight;
  }

  function drawManagedFittedWrappedText(ctx, state, kind, str, x, y, maxWidth, maxLines, startSize, minSize, color, family, weight='700', align='left', elementKey=kind){
    const adj = getElementAdjustments(state, kind, elementKey, color);
    const fitted = fitWrappedText(ctx, str, maxWidth, maxLines, startSize * adj.scale, Math.max(8, minSize * Math.min(adj.scale, 1.35)), family, weight);
    ctx.save();
    ctx.fillStyle = adj.color;
    ctx.textAlign = align;
    ctx.textBaseline = 'top';
    applyInputTextShadow(ctx);
    setFont(ctx, fitted.size, weight, family);
    const managedLineHeight = fitted.lineHeight * adj.lineHeightScale;
    fitted.lines.forEach((lineText, index) => {
      ctx.fillText(lineText, x + adj.dx, y + adj.dy + index * managedLineHeight);
    });
    ctx.restore();
    return {
      ...fitted,
      lineHeight:managedLineHeight,
      height: fitted.lines.length * managedLineHeight,
      x: x + adj.dx,
      y: y + adj.dy
    };
  }


  const watermarkImageCache = new Map();

  function creatorDisplayText(state){
    const name = String(state.creator || '').trim();
    if(!name) return '';
    const format = state.creatorFormat || 'copyright';
    const year = String(state.date || '').slice(0,4) || String(new Date().getFullYear());
    if(format === 'photoBy') return `Photo by ${name}`;
    if(format === 'copyrightYear') return `Copyright © ${year} ${name}`;
    if(format === 'nameOnly') return name;
    return `© ${name}`;
  }

  function getWatermarkImage(dataUrl){
    if(!dataUrl) return null;
    if(watermarkImageCache.has(dataUrl)) return watermarkImageCache.get(dataUrl);
    const record = {image:new Image(), loaded:false, failed:false};
    record.image.onload = () => { record.loaded = true; renderPreview(); };
    record.image.onerror = () => { record.failed = true; };
    record.image.src = dataUrl;
    watermarkImageCache.set(dataUrl, record);
    return record;
  }

  function drawTintedWatermarkImage(ctx, imageObject, x, y, width, height, color){
    const temp = document.createElement('canvas');
    temp.width = Math.max(1, Math.round(width));
    temp.height = Math.max(1, Math.round(height));
    const tctx = temp.getContext('2d');
    if(!tctx) return;
    tctx.drawImage(imageObject, 0, 0, temp.width, temp.height);
    tctx.globalCompositeOperation = 'source-in';
    tctx.fillStyle = color || '#ffffff';
    tctx.fillRect(0,0,temp.width,temp.height);
    ctx.drawImage(temp, x, y, width, height);
  }

  function drawUniversalOverlays(ctx, state, model){
    const metaFont = state.metaFont || "'Pretendard', sans-serif";
    const activeLayout = state.layout || layout;
    const brushOverlay = activeLayout === 'brush';
    const brushMargin = Number(state.margin || 0);
    const overlayLeft = brushOverlay ? brushMargin + 48 : 34;
    const overlayRight = brushOverlay ? model.width - brushMargin - 48 : model.width - 34;
    const overlayBottom = brushOverlay ? model.height - brushMargin - 46 : model.height - 28;
    if(isActiveSetting(state,'showCreator')){
      const text = creatorDisplayText(state);
      if(text){
        const adj = getElementAdjustments(state, 'meta', 'creator', state.creatorColor || '#ffffff');
        const size = 18 * adj.scale;
        ctx.save();
        ctx.textAlign = 'right';
        ctx.textBaseline = 'alphabetic';
        ctx.fillStyle = state.creatorColor || adj.color;
        applyInputTextShadow(ctx);
        setFont(ctx, size, '600', metaFont);
        ctx.fillText(text, overlayRight + adj.dx, overlayBottom + adj.dy);
        ctx.restore();
      }
    }
    if(isActiveSetting(state,'showWatermark')){
      const adj = getElementAdjustments(state, 'meta', 'watermark', state.watermarkColor || '#ffffff');
      const dataUrl = state.watermarkDataUrl || '';
      const record = getWatermarkImage(dataUrl);
      if(record && record.loaded && !record.failed){
        const sourceW = record.image.naturalWidth || 1;
        const sourceH = record.image.naturalHeight || 1;
        const targetW = Math.min(model.width * 0.28, 260) * adj.scale;
        const targetH = targetW * sourceH / sourceW;
        const x = overlayLeft + adj.dx;
        const y = overlayBottom - targetH + adj.dy;
        ctx.save();
        applyInputTextShadow(ctx);
        drawTintedWatermarkImage(ctx, record.image, x, y, targetW, targetH, state.watermarkColor || '#ffffff');
        ctx.restore();
      }else if(state.watermarkText){
        const size = 18 * adj.scale;
        ctx.save();
        ctx.textAlign = 'left';
        ctx.textBaseline = 'alphabetic';
        ctx.fillStyle = state.watermarkColor || '#ffffff';
        applyInputTextShadow(ctx);
        setFont(ctx, size, '600', metaFont);
        ctx.fillText(String(state.watermarkText), overlayLeft + adj.dx, overlayBottom + adj.dy);
        ctx.restore();
      }
    }
  }

  function stars(ctx, x, y, n, color, size, family, align='left'){
    ctx.save();
    setFont(ctx, size, '700', family);
    ctx.textBaseline = 'alphabetic';

    const filledWidth = ctx.measureText('★').width;
    const emptyWidth = ctx.measureText('☆').width;
    const step = Math.max(filledWidth, emptyWidth) + size * 0.16;
    const totalWidth = step * 4 + Math.max(filledWidth, emptyWidth);
    let cursor = align === 'right' ? x - totalWidth : x;

    for(let i=0;i<5;i++){
      const filled = i < n;
      ctx.fillStyle = filled ? color : '#b7b7b7';
      const glyph = filled ? '★' : '☆';
      ctx.fillText(glyph, cursor, y);
      cursor += step;
    }
    ctx.restore();
    return totalWidth;
  }

  function logoPaths(key){
    return ['svg','png','jpg','jpeg','webp'].map(ext => `assets/logos/${key}.${ext}`);
  }

  function requestLocalLogo(theme){
    if(!theme || !theme.key) return null;
    const cacheKey = theme.dataUrl ? `${theme.key}:${theme.dataUrl}` : theme.key;
    if(logoCache.has(cacheKey)) return logoCache.get(cacheKey);

    const img = new Image();
    const record = {
      img,
      loaded:false,
      failed:false,
      embedded:false
    };

    logoCache.set(cacheKey, record);

    img.onload = () => {
      record.loaded = true;
      renderPreview();
    };

    img.onerror = () => {
      record.failed = true;
      renderPreview();
    };

    if(theme.dataUrl){
      record.embedded = true;
      img.src = theme.dataUrl;
      return record;
    }

    const embeddedSource = EMBEDDED_LOGOS[theme.key];

    if(embeddedSource){
      record.embedded = true;
      img.src = embeddedSource;
      return record;
    }

    /*
      Fallback retained only for future logos not embedded in this build.
      Supplied brand logos never use this path.
    */
    const paths = logoPaths(theme.key);
    let index = 0;

    const tryNext = () => {
      if(index >= paths.length){
        record.failed = true;
        renderPreview();
        return;
      }

      img.onload = () => {
        record.loaded = true;
        renderPreview();
      };

      img.onerror = () => {
        index += 1;
        tryNext();
      };

      img.src = paths[index];
    };

    tryNext();
    return record;
  }

  function preloadEmbeddedLogos(){
    Object.keys(EMBEDDED_LOGOS).forEach(key => {
      const theme = Object.values(BRANDS).find(item => item.key === key);
      if(theme) requestLocalLogo(theme);
    });
  }

  function drawBrand(ctx, theme, state, x, y, maxW, maxH, family, align='left', fallbackColor=null, elementKey='logo'){
    if(!isActiveSetting(state, 'showLogo')){
      return {w:0, h:0, visible:false};
    }

    const logoAdj = getElementAdjustments(state, 'meta', elementKey, fallbackColor || theme.accent);
    x += logoAdj.dx;
    y += logoAdj.dy;
    maxW *= logoAdj.scale;
    maxH *= logoAdj.scale;

    if(theme.textOnly){
      const brandText = String(theme.brand || state.make || 'CAMERA').trim();
      const fontSize = Math.min(maxH * .78, 28);
      const color = logoAdj.color;
      drawText(ctx, brandText, x, y + maxH * .78, fontSize, color, '700', family, align);
      return {w:maxW, h:maxH, visible:true};
    }

    const rec = requestLocalLogo(theme);
    if(rec && rec.loaded && rec.img.naturalWidth){
      const ratio = rec.img.naturalWidth / rec.img.naturalHeight;
      let w = maxW, h = w / ratio;
      if(h > maxH){ h = maxH; w = h * ratio; }
      const dx = align === 'right' ? x - w : x;
      ctx.drawImage(rec.img, dx, y, w, h);
      return {w, h, visible:true};
    }

    if(rec && rec.failed){
      const fontSize = Math.min(maxH * .78, 28);
      const color = logoAdj.color;
      drawText(ctx, theme.brand, x, y + maxH * .78, fontSize, color, '700', family, align);
      return {w:maxW, h:maxH, visible:true};
    }

    return {w:0, h:0, visible:false};
  }

  // 16-segment vector display for Film Date Overlay.
  // Vector rendering is used instead of a font file so preview and JPEG export
  // remain identical across iOS, Windows, macOS and browsers.
  const SEG16_POINTS = {
    A1:[0.16,0.10, 0.47,0.10], A2:[0.53,0.10, 0.84,0.10],
    B:[0.88,0.15, 0.88,0.46], C:[0.88,0.54, 0.88,0.85],
    D1:[0.53,0.90, 0.84,0.90], D2:[0.16,0.90, 0.47,0.90],
    E:[0.12,0.54, 0.12,0.85], F:[0.12,0.15, 0.12,0.46],
    G1:[0.16,0.50, 0.47,0.50], G2:[0.53,0.50, 0.84,0.50],
    H:[0.18,0.15, 0.46,0.46], I:[0.50,0.14, 0.50,0.46],
    J:[0.82,0.15, 0.54,0.46], K:[0.18,0.85, 0.46,0.54],
    L:[0.50,0.54, 0.50,0.86], M:[0.82,0.85, 0.54,0.54]
  };

  const SEG16_MAP = {
    '0':['A1','A2','B','C','D1','D2','E','F'],
    '1':['B','C'],
    '2':['A1','A2','B','G1','G2','E','D2','D1'],
    '3':['A1','A2','B','G1','G2','C','D1','D2'],
    '4':['F','G1','G2','B','C'],
    '5':['A1','A2','F','G1','G2','C','D1','D2'],
    '6':['A1','A2','F','G1','G2','E','C','D1','D2'],
    '7':['A1','A2','B','C'],
    '8':['A1','A2','B','C','D1','D2','E','F','G1','G2'],
    '9':['A1','A2','B','C','D1','D2','F','G1','G2'],
    'A':['A1','A2','B','C','E','F','G1','G2'],
    'B':['A1','A2','B','C','D1','D2','G1','G2','I','L'],
    'C':['A1','A2','D1','D2','E','F'],
    'D':['A1','A2','B','C','D1','D2','I','L'],
    'E':['A1','A2','D1','D2','E','F','G1','G2'],
    'F':['A1','A2','E','F','G1','G2'],
    'G':['A1','A2','C','D1','D2','E','F','G2'],
    'H':['B','C','E','F','G1','G2'],
    'I':['A1','A2','D1','D2','I','L'],
    'J':['B','C','D1','D2','E'],
    'K':['E','F','G1','J','M'],
    'L':['D1','D2','E','F'],
    'M':['B','C','E','F','H','J'],
    'N':['B','C','E','F','H','M'],
    'O':['A1','A2','B','C','D1','D2','E','F'],
    'P':['A1','A2','B','E','F','G1','G2'],
    'Q':['A1','A2','B','C','D1','D2','E','F','M'],
    'R':['A1','A2','B','E','F','G1','G2','M'],
    'S':['A1','A2','F','G1','G2','C','D1','D2'],
    'T':['A1','A2','I','L'],
    'U':['B','C','D1','D2','E','F'],
    'V':['E','F','K','M'],
    'W':['B','C','E','F','K','M'],
    'X':['H','J','K','M'],
    'Y':['H','J','L'],
    'Z':['A1','A2','J','K','D1','D2'],
    '-':['G1','G2'],
    '_':['D1','D2'],
    ' ' :[]
  };

  function digitalCharWidth(size){ return size * 0.64; }
  function digitalGap(size){ return size * 0.12; }

  function measureDigitalText(text, size){
    const chars = String(text || '').toUpperCase();
    let total = 0;
    for(let i=0;i<chars.length;i++){
      const ch = chars[i];
      if(ch === '.') total += size * 0.18;
      else if(ch === ':') total += size * 0.22;
      else if(ch === '/') total += size * 0.34;
      else total += digitalCharWidth(size);
      if(i < chars.length - 1) total += digitalGap(size);
    }
    return total;
  }

  function drawSegment16(ctx, x1, y1, x2, y2, thickness){
    ctx.beginPath();
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.lineWidth = thickness;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.stroke();
  }

  function drawDigitalText(ctx, text, x, y, size, color, align='left'){
    const chars = String(text || '').toUpperCase();
    const thickness = Math.max(1.35, size * 0.072);
    const gap = digitalGap(size);
    const totalWidth = measureDigitalText(chars, size);
    let cursor = x;
    if(align === 'right') cursor = x - totalWidth;
    if(align === 'center') cursor = x - totalWidth / 2;

    ctx.save();
    ctx.strokeStyle = color;
    ctx.fillStyle = color;
    ctx.globalAlpha = 0.98;
    ctx.shadowColor = 'rgba(255,130,20,.20)';
    ctx.shadowBlur = Math.max(0.5, size * 0.025);

    [...chars].forEach(ch => {
      const cw = ch === '.' ? size * 0.18 : ch === ':' ? size * 0.22 : ch === '/' ? size * 0.34 : digitalCharWidth(size);
      if(ch === '.'){
        ctx.beginPath();
        ctx.arc(cursor + cw * 0.5, y + size * 0.86, thickness * 0.62, 0, Math.PI * 2);
        ctx.fill();
      } else if(ch === ':'){
        [0.35,0.69].forEach(py => {
          ctx.beginPath();
          ctx.arc(cursor + cw * 0.5, y + size * py, thickness * 0.55, 0, Math.PI * 2);
          ctx.fill();
        });
      } else if(ch === '/'){
        drawSegment16(ctx, cursor + cw * 0.12, y + size * 0.88, cursor + cw * 0.88, y + size * 0.12, thickness);
      } else {
        const segs = SEG16_MAP[ch] || [];
        segs.forEach(seg => {
          const [x1,y1,x2,y2] = SEG16_POINTS[seg];
          drawSegment16(ctx, cursor + cw*x1, y + size*y1, cursor + cw*x2, y + size*y2, thickness);
        });
      }
      cursor += cw + gap;
    });
    ctx.restore();
  }

  function horizontalAnchor(position, left, right){
    const p = Math.max(0, Math.min(100, Number(position || 0)));
    const x = left + (right - left) * (p / 100);

    if(p <= 33){
      return {
        x,
        align:'left',
        maxWidth:Math.max(40, right - x)
      };
    }

    if(p >= 67){
      return {
        x,
        align:'right',
        maxWidth:Math.max(40, x - left)
      };
    }

    return {
      x,
      align:'center',
      maxWidth:Math.max(40, Math.min(x - left, right - x) * 2)
    };
  }

  function fitHorizontalPosterText(ctx, text, maxWidth, maxLines, wantedSize, minSize, family, weight){
    return fitWrappedText(
      ctx,
      text,
      maxWidth,
      maxLines,
      wantedSize,
      minSize,
      family,
      weight
    );
  }

  function buildVerticalColumns(text, maxCharsPerColumn){
    const normalized = String(text || '').replace(/\r/g, '');
    const columns = [];
    let column = [];

    for(const character of normalized){
      if(character === '\n' || column.length >= maxCharsPerColumn){
        if(column.length) columns.push(column);
        column = [];
        if(character === '\n') continue;
      }
      column.push(character);
    }

    if(column.length) columns.push(column);
    return columns;
  }

  function drawVerticalPosterText(ctx, text, anchorX, anchorY, maxHeight, fontSize, minSize, color, family, weight='700', align='left', maxColumns=5){
    let size = fontSize;
    let columns = [];

    while(size >= minSize){
      const lineHeight = size * 1.05;
      const maxChars = Math.max(1, Math.floor(maxHeight / lineHeight));
      columns = buildVerticalColumns(text, maxChars);
      if(columns.length <= maxColumns) break;
      size -= 2;
    }

    size = Math.max(minSize, size);
    const lineHeight = size * 1.05;
    const columnGap = size * 1.18;
    const maxChars = Math.max(1, Math.floor(maxHeight / lineHeight));
    columns = buildVerticalColumns(text, maxChars).slice(0, maxColumns);

    const totalWidth = Math.max(size, columns.length * columnGap);
    let firstColumnX = anchorX;

    if(align === 'right'){
      firstColumnX = anchorX;
    }else if(align === 'center'){
      firstColumnX = anchorX + totalWidth / 2 - size / 2;
    }else{
      firstColumnX = anchorX + totalWidth - size;
    }

    ctx.save();
    ctx.fillStyle = color;
    ctx.textAlign = 'center';
    ctx.textBaseline = 'top';
    ctx.shadowColor = 'rgba(0,0,0,0.32)';
    ctx.shadowBlur = 2;
    ctx.shadowOffsetY = 1;
    setFont(ctx, size, weight, family);

    columns.forEach((column, columnIndex) => {
      const columnX = firstColumnX - columnIndex * columnGap;
      column.forEach((character, charIndex) => {
        ctx.fillText(character, columnX, anchorY + charIndex * lineHeight);
      });
    });

    ctx.restore();
    return {size, width:totalWidth, height:Math.min(maxHeight, maxChars * lineHeight)};
  }


  const photoDataAnalysisCache = new Map();

  function photoDataRatioLabel(width, height){
    if(!width || !height) return '—';
    const ratio = width / height;
    const candidates = [
      ['1:1',1],['3:2',3/2],['2:3',2/3],['4:3',4/3],['3:4',3/4],
      ['16:9',16/9],['9:16',9/16],['5:4',5/4],['4:5',4/5]
    ];
    let best = candidates[0];
    let difference = Infinity;
    candidates.forEach(candidate => {
      const nextDifference = Math.abs(ratio - candidate[1]);
      if(nextDifference < difference){ best = candidate; difference = nextDifference; }
    });
    if(difference < 0.035) return best[0];
    const gcd = (a,b) => b ? gcd(b, a % b) : a;
    const divisor = gcd(Math.round(width), Math.round(height)) || 1;
    const left = Math.round(width / divisor);
    const right = Math.round(height / divisor);
    return left <= 50 && right <= 50 ? `${left}:${right}` : ratio.toFixed(2);
  }

  function photoDataHex(r,g,b){
    return `#${[r,g,b].map(value => Math.max(0,Math.min(255,Math.round(value))).toString(16).padStart(2,'0')).join('').toUpperCase()}`;
  }

  function analyzePhotoForData(){
    if(!imageLoaded || !image.naturalWidth || !image.naturalHeight){
      return {
        width:0,height:0,megapixels:0,ratio:'—',brightness:0,
        average:'#808080',palette:['#222222','#555555','#888888','#BBBBBB','#EEEEEE'],
        histogram:{r:new Array(32).fill(0),g:new Array(32).fill(0),b:new Array(32).fill(0),max:1}
      };
    }

    const key = `${image.currentSrc || image.src}:${image.naturalWidth}x${image.naturalHeight}`;
    if(photoDataAnalysisCache.has(key)) return photoDataAnalysisCache.get(key);

    const maxSampleEdge = 180;
    const ratio = image.naturalWidth / image.naturalHeight;
    const sampleW = ratio >= 1 ? maxSampleEdge : Math.max(1,Math.round(maxSampleEdge * ratio));
    const sampleH = ratio >= 1 ? Math.max(1,Math.round(maxSampleEdge / ratio)) : maxSampleEdge;
    const canvas = document.createElement('canvas');
    canvas.width = sampleW;
    canvas.height = sampleH;
    const ctx = canvas.getContext('2d', {willReadFrequently:true});
    ctx.drawImage(image,0,0,sampleW,sampleH);
    const pixels = ctx.getImageData(0,0,sampleW,sampleH).data;

    const bins = 32;
    const histR = new Array(bins).fill(0);
    const histG = new Array(bins).fill(0);
    const histB = new Array(bins).fill(0);
    const buckets = new Map();
    let sumR=0,sumG=0,sumB=0,sumL=0,count=0;

    for(let index=0; index<pixels.length; index+=4){
      const alpha = pixels[index+3];
      if(alpha < 16) continue;
      const r=pixels[index], g=pixels[index+1], b=pixels[index+2];
      sumR+=r; sumG+=g; sumB+=b;
      sumL += 0.2126*r + 0.7152*g + 0.0722*b;
      count++;
      histR[Math.min(bins-1, r >> 3)]++;
      histG[Math.min(bins-1, g >> 3)]++;
      histB[Math.min(bins-1, b >> 3)]++;
      const qr = r >> 5, qg = g >> 5, qb = b >> 5;
      const bucketKey = `${qr}:${qg}:${qb}`;
      const bucket = buckets.get(bucketKey) || {count:0,r:0,g:0,b:0};
      bucket.count++; bucket.r+=r; bucket.g+=g; bucket.b+=b;
      buckets.set(bucketKey,bucket);
    }

    const safeCount = Math.max(1,count);
    const avgR=sumR/safeCount, avgG=sumG/safeCount, avgB=sumB/safeCount;
    const palette=[];
    const selected=[];
    [...buckets.values()].sort((a,b)=>b.count-a.count).forEach(bucket => {
      if(palette.length >= 5) return;
      const color=[bucket.r/bucket.count,bucket.g/bucket.count,bucket.b/bucket.count];
      const distant = selected.every(existing => {
        const dr=color[0]-existing[0], dg=color[1]-existing[1], db=color[2]-existing[2];
        return Math.sqrt(dr*dr+dg*dg+db*db) > 54;
      });
      if(distant){ selected.push(color); palette.push(photoDataHex(...color)); }
    });
    while(palette.length < 5){
      const factor = 0.55 + palette.length * 0.12;
      palette.push(photoDataHex(avgR*factor,avgG*factor,avgB*factor));
    }

    const histogramMax = Math.max(1,...histR,...histG,...histB);
    const analysis = {
      width:image.naturalWidth,
      height:image.naturalHeight,
      megapixels:image.naturalWidth*image.naturalHeight/1000000,
      ratio:photoDataRatioLabel(image.naturalWidth,image.naturalHeight),
      brightness:Math.round((sumL/safeCount)/255*100),
      average:photoDataHex(avgR,avgG,avgB),
      palette,
      histogram:{r:histR,g:histG,b:histB,max:histogramMax}
    };
    photoDataAnalysisCache.set(key,analysis);
    if(photoDataAnalysisCache.size > 30){
      const oldestKey=photoDataAnalysisCache.keys().next().value;
      photoDataAnalysisCache.delete(oldestKey);
    }
    return analysis;
  }

  function drawPhotoDataHistogram(ctx, analysis, x, y, width, height){
    ctx.save();
    ctx.fillStyle='#111418';
    ctx.fillRect(x,y,width,height);
    ctx.strokeStyle='rgba(255,255,255,0.10)';
    ctx.lineWidth=1;
    for(let i=1;i<4;i++){
      const gy=y+height*i/4;
      ctx.beginPath(); ctx.moveTo(x,gy); ctx.lineTo(x+width,gy); ctx.stroke();
    }
    const series=[['r','#E85C55'],['g','#66B875'],['b','#5C82E8']];
    series.forEach(([key,color])=>{
      const values=analysis.histogram[key];
      ctx.strokeStyle=color;
      ctx.lineWidth=2;
      ctx.beginPath();
      values.forEach((value,index)=>{
        const px=x+(index/(values.length-1))*width;
        const py=y+height-(value/analysis.histogram.max)*(height-8)-4;
        if(index===0) ctx.moveTo(px,py); else ctx.lineTo(px,py);
      });
      ctx.stroke();
    });
    ctx.strokeStyle='rgba(0,0,0,0.45)';
    ctx.strokeRect(x,y,width,height);
    ctx.restore();
  }

  function drawPhotoDataPalette(ctx, analysis, x, y, width, height, gap=8){
    const colors=analysis.palette.slice(0,5);
    const swatchW=(width-gap*(colors.length-1))/colors.length;
    colors.forEach((color,index)=>{
      ctx.fillStyle=color;
      ctx.fillRect(x+index*(swatchW+gap),y,swatchW,height);
    });
  }

  function drawPhotoDataBrightness(ctx, analysis, x, y, width, color){
    ctx.save();
    ctx.fillStyle='rgba(0,0,0,0.12)';
    ctx.fillRect(x,y,width,7);
    ctx.fillStyle=color;
    ctx.fillRect(x,y,width*Math.max(0,Math.min(100,analysis.brightness))/100,7);
    ctx.restore();
  }

  function buildModel(state, measureCtx){
    const theme = effectiveTheme(state);
    const m = Number(state.margin);
    const radius = Number(state.radius);
    const ratio = photoRatio();
    const photoW = 1000;
    const photoH = photoW / ratio;
    const frameColor = state.frameColor;

    const fonts = { title: state.titleFont, body: state.bodyFont, meta: state.metaFont };

    const useCustomTextColors = state.textColorMode === 'custom';
    const lightPalette = {
      title: useCustomTextColors ? state.titleColor : '#171717',
      body: useCustomTextColors ? state.bodyColor : '#171717',
      meta: useCustomTextColors ? state.metaColor : '#5f5f5f'
    };
    const darkPalette = {
      title: useCustomTextColors ? state.titleColor : '#ffffff',
      body: useCustomTextColors ? state.bodyColor : '#f0f0f0',
      meta: useCustomTextColors ? state.metaColor : '#d8d8d8'
    };


    if(layout === 'stamp'){
      const W = photoW;
      const H = photoH;
      return {
        width: W, height: H,
        draw(ctx){
          ctx.fillStyle = '#111';
          ctx.fillRect(0,0,W,H);
          drawPhoto(ctx, 0, 0, W, H, 0);

          const stampColor = '#ff9f2e';
          const bottomOffset = Math.max(16, H * 0.035);
          const baseSize = Math.max(11, Math.min(16, H * 0.022));
          const lineTop = H - bottomOffset - baseSize;
          const brandStr = theme.brand.toUpperCase();
          const exifStr = stampExifLine(state);
          const dateStr = dateText(state).slice(2);

          const leftPad = Math.max(12, W * 0.018);
          const rightPad = leftPad;
          const brandMax = W * 0.19;
          const exifMax = W * 0.49;
          const dateMax = W * 0.22;

          function fittedSize(text, wanted, maxWidth, minSize=8){
            let size = wanted;
            while(size > minSize && measureDigitalText(text, size) > maxWidth) size -= 0.5;
            return size;
          }

          const logoAdj = getElementAdjustments(state, 'meta', 'logo', stampColor);
          const exifAdj = getElementAdjustments(state, 'exif', 'exif', stampColor);
          const brandSize = fittedSize(brandStr, baseSize * logoAdj.scale, brandMax, 8);
          const exifSize = fittedSize(exifStr, baseSize * exifAdj.scale, exifMax, 8);
          const dateSize = fittedSize(dateStr, (baseSize + 1) * exifAdj.scale, dateMax, 8);

          if(isActiveSetting(state, 'showLogo')){
            drawDigitalText(ctx, brandStr, leftPad + logoAdj.dx, lineTop + logoAdj.dy, brandSize, stampColor, 'left');
          }
          if(isActiveSetting(state, 'showExif')){
            drawDigitalText(ctx, exifStr, W * 0.49 + exifAdj.dx, lineTop + exifAdj.dy, exifSize, stampColor, 'center');
            drawDigitalText(ctx, dateStr, W - rightPad + exifAdj.dx, lineTop + exifAdj.dy, dateSize, stampColor, 'right');
          }
        }
      };
    }

    if(layout === 'gallery'){
      const footerBase = 168;
      const projectH = isActiveSetting(state,'showProject') ? 34 : 0;
      const noteLines = isActiveSetting(state,'showNote') ? wrapLines(measureCtx, state.note, photoW, 18, fonts.body, '400', 4).length : 0;
      const footer = footerBase + projectH + noteLines * 26;
      const W = photoW + m * 2;
      const H = photoH + m * 2 + footer;
      return {
        width: W, height: H,
        draw(ctx){
          const fg = lightPalette.title;
          const bodyFg = lightPalette.body;
          const muted = lightPalette.meta;
          drawFrameSurface(ctx, 0, 0, W, H, frameColor);
          drawPhoto(ctx, m, m, photoW, photoH, radius);

          const metaTop = m + photoH + 34;
          const showBrand = isActiveSetting(state,'showLogo');
          const showExif = isActiveSetting(state,'showExif');

          if(showBrand) drawBrand(ctx, theme, state, m, metaTop - 8, 250, 30, fonts.meta, 'left', lightPalette.meta);

          if(showExif){
            drawManagedText(ctx, state, 'exif', state.model, W - m, metaTop + 18, 28, lightPalette.meta, '700', fonts.meta, 'right');
            drawManagedFittedText(ctx, state, 'exif', state.lens, m, metaTop + 52, W * 0.58, 22, 12, lightPalette.meta, '500', fonts.meta);
            drawManagedFittedText(ctx, state, 'exif', exifLine(state), m, metaTop + 86, W * 0.62, 21, 11, lightPalette.meta, '400', fonts.meta);
            if(isActiveSetting(state,'showLocation')){
              drawManagedFittedText(ctx, state, 'location', `${dateText(state)}  ${state.location}`, W - m, metaTop + 86, W * 0.34, 20, 11, lightPalette.meta, '400', fonts.meta, 'right');
            } else {
              drawManagedFittedText(ctx, state, 'exif', `${dateText(state)}`, W - m, metaTop + 86, W * 0.24, 20, 11, lightPalette.meta, '400', fonts.meta, 'right');
            }
          } else if(isActiveSetting(state,'showLocation')){
            drawManagedFittedText(ctx, state, 'location', state.location, W - m, metaTop + 20, W * 0.42, 21, 12, lightPalette.meta, '500', fonts.meta, 'right');
          }

          let yy = metaTop + (showExif ? 122 : 58);
          if(isActiveSetting(state,'showProject')){
            drawManagedText(ctx, state, 'meta', 'PROJECT', m, yy, 15, muted, '700', fonts.meta, 'left', false, 'project');
            drawManagedText(ctx, state, 'body', state.project, m + 92, yy, 22, fg, '700', fonts.title, 'left', false, 'project');
            yy += 28;
          }
          if(isActiveSetting(state,'showNote')){
            drawManagedWrappedText(ctx, state, 'body', state.note, m, yy, W - 2*m, 27, 18, lightPalette.body, fonts.body, '400', 4, 'left', 'note');
          }
        }
      };
    }

    if(layout === 'contact'){
      const topInfoBand = 44;
      const photoY = 98;
      const afterPhotoGap = 28;
      const titleH = isActiveSetting(state,'showTitle') ? 36 : 0;
      const promptH = isActiveSetting(state,'showPrompt') ? 26 : 0;
      const thoughtLines = isActiveSetting(state,'showThought') ? wrapLines(measureCtx, state.thought, photoW - 60, 23, fonts.body, '400', 5).length : 0;
      const thoughtH = isActiveSetting(state,'showThought') ? thoughtLines * 32 : 0;
      const infoBottomBand = 46;
      const contentBlockH = titleH + promptH + thoughtH + 18;
      const bottomSafeGap = 34;
      const W = photoW + (m + 28) * 2;
      const H = photoY + photoH + afterPhotoGap + contentBlockH + bottomSafeGap + infoBottomBand + 52;
      return {
        width: W, height: H,
        draw(ctx){
          ctx.fillStyle = '#0a0a0a';
          ctx.fillRect(0,0,W,H);

          const holeCount = 16;
          const innerW = W - 2*m;
          for(let i=0;i<holeCount;i++){
            const hx = m + i * (innerW / holeCount) + 4;
            ctx.fillStyle = '#c8c8c8';
            roundedRectPath(ctx, hx, 14, 32, 40, 6); ctx.fill();
            roundedRectPath(ctx, hx, H - 54, 32, 40, 6); ctx.fill();
          }

          const showBrand = isActiveSetting(state,'showLogo');
          const showExif = isActiveSetting(state,'showExif');

          if(showBrand) drawBrand(ctx, theme, state, m + 14, 62, 200, 24, fonts.meta, 'left', darkPalette.meta);
          if(showExif) drawManagedFittedText(ctx, state, 'exif', exifLine(state), W - (m + 14), 82, W * 0.42, 18, 11, darkPalette.meta, '600', fonts.meta, 'right');

          const photoX = m + 28;
          drawPhoto(ctx, photoX, photoY, photoW, photoH, radius);
          ctx.strokeStyle = '#252525';
          ctx.lineWidth = 8;
          ctx.strokeRect(photoX, photoY, photoW, photoH);

          let yy = photoY + photoH + afterPhotoGap;
          if(isActiveSetting(state,'showTitle')){
            drawManagedText(ctx, state, 'title', state.title, W/2, yy, 28, darkPalette.title, '700', fonts.title, 'center');
            yy += 36;
          }
          if(isActiveSetting(state,'showPrompt')){
            drawManagedText(ctx, state, 'body', state.promptText, W/2, yy, 17, darkPalette.meta, '600', fonts.body, 'center', false, 'prompt');
            yy += 26;
          }
          if(isActiveSetting(state,'showThought')){
            drawManagedWrappedText(ctx, state, 'body', state.thought, W/2, yy, photoW - 60, 32, 23, darkPalette.body, fonts.body, '400', 5, 'center', 'thought');
          }

          const bottomInfoY = H - 70;
          if(showExif){
            drawManagedFittedText(ctx, state, 'exif', state.model, m + 14, bottomInfoY, W * 0.42, 18, 12, darkPalette.meta, '500', fonts.meta);
            drawManagedFittedText(ctx, state, 'exif', dateText(state), W - (m + 14), bottomInfoY, W * 0.20, 18, 12, darkPalette.meta, '600', fonts.meta, 'right');
          }
        }
      };
    }

    if(layout === 'poster'){
      const showTitle = isActiveSetting(state,'showTitle');
      const showThought = isActiveSetting(state,'showThought');
      const showLocation = isActiveSetting(state,'showLocation');
      const showProject = isActiveSetting(state,'showProject');
      const showBrand = isActiveSetting(state,'showLogo');
      const showExif = isActiveSetting(state,'showExif');

      // Poster Overlay is photo-only: no outer frame, no external margin.
      const W = photoW;
      const H = photoH;

      return {
        width: W, height: H,
        draw(ctx){
          drawPhoto(ctx, 0, 0, photoW, photoH, 0);

          const photoTop = 0;
          const photoBottom = photoH;
          const photoLeft = 0;
          const photoRight = photoW;

          // Visual safe area for project, logo, location, and EXIF.
          // Text no longer sits directly on the photo/frame edge.
          const edgeInsetX = Math.max(26, Math.min(44, photoW * 0.038));
          const edgeInsetTop = Math.max(28, Math.min(42, photoH * 0.048));
          const edgeInsetBottom = Math.max(30, Math.min(46, photoH * 0.052));
          const contentLeft = photoLeft + edgeInsetX;
          const contentRight = photoRight - edgeInsetX;

          const topReserve = Math.max(64, photoH * 0.11);
          const bottomReserve = Math.max(60, photoH * 0.10);

          const lowerGradientH = Math.max(300, photoH * 0.62);
          fillGradientRect(
            ctx,
            photoLeft,
            photoBottom - lowerGradientH,
            photoW,
            lowerGradientH,
            'vertical',
            [
              [0, 'rgba(0,0,0,0)'],
              [0.40, 'rgba(0,0,0,0.16)'],
              [0.72, 'rgba(0,0,0,0.56)'],
              [1, 'rgba(0,0,0,0.82)']
            ]
          );

          const upperGradientH = Math.max(100, photoH * 0.18);
          fillGradientRect(
            ctx,
            photoLeft,
            photoTop,
            photoW,
            upperGradientH,
            'vertical',
            [
              [0, 'rgba(0,0,0,0.48)'],
              [1, 'rgba(0,0,0,0)']
            ]
          );

          const identityY = photoTop + edgeInsetTop;

          if(showProject){
            drawManagedFittedText(
              ctx,
              state,
              'meta',
              state.project.toUpperCase(),
              contentLeft,
              identityY,
              photoW * 0.44,
              19,
              11,
              darkPalette.meta,
              '700',
              fonts.meta,
              'left',
              'project'
            );
          }

          if(showBrand){
            drawBrand(
              ctx,
              theme,
              state,
              contentRight,
              identityY - 20,
              Math.min(190, photoW * 0.24),
              25,
              fonts.meta,
              'right',
              darkPalette.meta
            );
          }

          const titleAnchor = horizontalAnchor(state.posterTitleX, photoLeft, photoRight);
          const bodyAnchor = horizontalAnchor(state.posterBodyX, photoLeft, photoRight);
          const titlePosY = Math.max(0, Math.min(100, Number(state.posterTitleY || 72)));
          const bodyPosY = Math.max(0, Math.min(100, Number(state.posterBodyY || 84)));
          const titleAdj = getElementAdjustments(state, 'title', 'title', darkPalette.title);
          const bodyAdj = getElementAdjustments(state, 'body', 'thought', darkPalette.body);
          const locationAdj = getElementAdjustments(state, 'location', 'location', darkPalette.meta);
          const titleSize = Math.max(24, Math.min(140, Number(state.posterTitleSize || 66))) * titleAdj.scale;
          const bodySize = Math.max(12, Math.min(72, Number(state.posterBodySize || 22))) * bodyAdj.scale;
          const titleVertical = state.posterTitleDirection === 'vertical';
          const bodyVertical = state.posterBodyDirection === 'vertical';

          const contentTop = photoTop + topReserve;
          const contentBottom = photoBottom - bottomReserve;
          const contentHeight = Math.max(80, contentBottom - contentTop);

          const titleY = contentTop + contentHeight * (titlePosY / 100) + titleAdj.dy;
          const bodyY = contentTop + contentHeight * (bodyPosY / 100) + bodyAdj.dy;

          if(showTitle){
            if(titleVertical){
              const verticalTitleY = Math.max(photoTop, Math.min(titleY, photoBottom - 40));
              drawVerticalPosterText(
                ctx,
                state.title,
                titleAnchor.x + titleAdj.dx,
                verticalTitleY,
                Math.max(40, photoBottom - verticalTitleY),
                titleSize,
                20,
                titleAdj.color,
                fonts.title,
                '700',
                titleAnchor.align,
                6
              );
            }else{
              const fit = fitHorizontalPosterText(
                ctx,
                state.title,
                titleAnchor.maxWidth,
                5,
                titleSize,
                22,
                fonts.title,
                '700'
              );

              const titleHeight = fit.lines.length * fit.lineHeight;
              const boundedTitleY = Math.max(
                photoTop,
                Math.min(titleY, photoBottom - titleHeight)
              );

              ctx.save();
              ctx.fillStyle = titleAdj.color;
              ctx.textAlign = titleAnchor.align;
              ctx.textBaseline = 'top';
              ctx.shadowColor = 'rgba(0,0,0,0.16)';
              ctx.shadowBlur = 2;
              ctx.shadowOffsetX = 1;
              ctx.shadowOffsetY = 1;
              setFont(ctx, fit.size, '700', fonts.title);

              fit.lines.forEach((lineText, index) => {
                ctx.fillText(
                  lineText,
                  titleAnchor.x + titleAdj.dx,
                  boundedTitleY + index * fit.lineHeight
                );
              });
              ctx.restore();
            }
          }

          if(showThought){
            if(bodyVertical){
              const verticalBodyY = Math.max(photoTop, Math.min(bodyY, photoBottom - 30));
              drawVerticalPosterText(
                ctx,
                state.thought,
                bodyAnchor.x + bodyAdj.dx,
                verticalBodyY,
                Math.max(30, photoBottom - verticalBodyY),
                bodySize,
                11,
                bodyAdj.color,
                fonts.body,
                '500',
                bodyAnchor.align,
                8
              );
            }else{
              const fit = fitHorizontalPosterText(
                ctx,
                state.thought,
                bodyAnchor.maxWidth,
                7,
                bodySize,
                11,
                fonts.body,
                '500'
              );

              const bodyLineHeight = fit.lineHeight * bodyAdj.lineHeightScale;
              const bodyHeight = fit.lines.length * bodyLineHeight;
              const boundedBodyY = Math.max(
                photoTop,
                Math.min(bodyY, photoBottom - bodyHeight)
              );

              ctx.save();
              ctx.fillStyle = bodyAdj.color;
              ctx.textAlign = bodyAnchor.align;
              ctx.textBaseline = 'top';
              ctx.shadowColor = 'rgba(0,0,0,0.16)';
              ctx.shadowBlur = 2;
              ctx.shadowOffsetX = 1;
              ctx.shadowOffsetY = 1;
              setFont(ctx, fit.size, '500', fonts.body);

              fit.lines.forEach((lineText, index) => {
                ctx.fillText(
                  lineText,
                  bodyAnchor.x + bodyAdj.dx,
                  boundedBodyY + index * bodyLineHeight
                );
              });
              ctx.restore();
            }
          }

          const metadataY = photoBottom - edgeInsetBottom;

          if(showLocation){
            drawManagedFittedText(
              ctx,
              state,
              'location',
              state.location,
              contentLeft,
              metadataY,
              photoW * 0.38,
              16,
              10,
              locationAdj.color,
              '600',
              fonts.meta,
              'left'
            );
          }

          if(showExif){
            const exifBlock = [
              state.model,
              exifLine(state),
              dateText(state)
            ].filter(Boolean).join('  ·  ');

            drawManagedFittedText(
              ctx,
              state,
              'exif',
              exifBlock,
              contentRight,
              metadataY,
              photoW * 0.48,
              15,
              9,
              darkPalette.meta,
              '500',
              fonts.meta,
              'right'
            );
          }
        }
      };
    }

    if(layout === 'frameonly'){
      const W = photoW + m * 2;
      const H = photoH + m * 2;
      return {
        width: W, height: H,
        draw(ctx){
          drawFrameSurface(ctx, 0, 0, W, H, frameColor);
          drawPhoto(ctx, m, m, photoW, photoH, radius);
        }
      };
    }

    if(layout === 'minimal'){
      const showBrand = isActiveSetting(state,'showLogo');
      const showExif = isActiveSetting(state,'showExif');
      const showLocation = isActiveSetting(state,'showLocation');
      const barH = showExif ? 106 : 68;
      const W = photoW + m * 2;
      const H = photoH + m * 2 + barH;

      return {
        width: W, height: H,
        draw(ctx){
          const fg = lightPalette.title;
          const muted = lightPalette.meta;

          drawFrameSurface(ctx, 0, 0, W, H, frameColor);
          drawPhoto(ctx, m, m, photoW, photoH, radius);

          const barTop = m + photoH + 22;

          if(showBrand){
            drawBrand(ctx, theme, state, m, barTop - 2, 185, 26, fonts.meta, 'left', lightPalette.meta);
          }

          if(showExif){
            const modelX = showBrand ? m + 215 : m;
            drawManagedFittedText(ctx, state, 'exif', state.model, modelX, barTop + 20, W * 0.25, 21, 12, lightPalette.meta, '700', fonts.meta);
            drawManagedFittedText(ctx, state, 'exif', exifLine(state), W - m, barTop + 20, W * 0.44, 18, 10, lightPalette.meta, '500', fonts.meta, 'right');

            if(showLocation){
              drawManagedFittedText(ctx, state, 'location', state.location, m, barTop + 56, W * 0.55, 16, 10, muted, '500', fonts.meta);
            }
            drawManagedFittedText(ctx, state, 'exif', dateText(state), W - m, barTop + 56, W * 0.24, 16, 10, muted, '500', fonts.meta, 'right');
          } else if(showLocation){
            drawManagedFittedText(ctx, state, 'location', state.location, W - m, barTop + 24, W * 0.46, 18, 11, muted, '500', fonts.meta, 'right');
          }
        }
      };
    }

    if(layout === 'caption'){
      const showTitle = isActiveSetting(state,'showTitle');
      const showThought = isActiveSetting(state,'showThought');
      const showLocation = isActiveSetting(state,'showLocation');
      const showExif = isActiveSetting(state,'showExif');

      const thoughtLines = showThought
        ? wrapLines(measureCtx, state.thought, photoW, 25, fonts.body, '400', 5).length
        : 0;

      const titleH = showTitle ? 56 : 0;
      const thoughtH = showThought ? thoughtLines * 34 + 16 : 0;
      const bottomMetaGap = (showThought && (showLocation || showExif)) ? 20 : 0;
      const bottomLineH = (showLocation || showExif) ? 32 : 0;
      const captionH = 48 + titleH + thoughtH + bottomMetaGap + bottomLineH + 24;

      const W = photoW + m * 2;
      const H = photoH + m * 2 + captionH;

      return {
        width: W, height: H,
        draw(ctx){
          const fg = lightPalette.title;
          const bodyFg = lightPalette.body;
          const muted = lightPalette.meta;

          drawFrameSurface(ctx, 0, 0, W, H, frameColor);
          drawPhoto(ctx, m, m, photoW, photoH, radius);

          let yy = m + photoH + 50;

          if(showTitle){
            drawManagedFittedText(ctx, state, 'title', state.title, m, yy, photoW, 38, 18, fg, '700', fonts.title);
            yy += 54;
          }

          if(showThought){
            yy += drawManagedWrappedText(ctx, state, 'body', state.thought, m, yy, photoW, 34, 25, bodyFg, fonts.body, '400', 5, 'left', 'thought');
            yy += 16;
          }

          if(showThought && (showLocation || showExif)){
            yy += bottomMetaGap;
          }

          if(showLocation){
            drawManagedFittedText(ctx, state, 'location', state.location, m, yy, photoW * 0.52, 18, 10, muted, '600', fonts.meta);
          }

          if(showExif){
            const exifBlock = [state.model, exifLine(state), dateText(state)]
              .filter(Boolean)
              .join('  ·  ');
            drawManagedFittedText(ctx, state, 'exif', exifBlock, W - m, yy, photoW * 0.46, 17, 9, muted, '500', fonts.meta, 'right');
          }
        }
      };
    }


    if(layout === 'photodata'){
      const analysis = analyzePhotoForData();
      const panelGap = 46;
      const panelWidth = 430;
      const panelMinHeight = 820;
      const contentHeight = Math.max(photoH, panelMinHeight);
      const W = photoW + panelGap + panelWidth + m * 2;
      const H = contentHeight + m * 2;

      return {
        width:W,
        height:H,
        draw(ctx){
          const fg=lightPalette.title;
          const muted=lightPalette.meta;
          const locationColor=useCustomTextColors ? state.locationColor : muted;
          drawFrameSurface(ctx,0,0,W,H,frameColor);

          const rowLabel=(label,x,y)=>drawText(ctx,label,x,y,12,muted,'700',fonts.meta);
          const rowValue=(value,x,y,maxWidth,align='left')=>drawFittedText(ctx,String(value||'—'),x,y,maxWidth,16,10,fg,'500',fonts.meta,align);
          const cameraText=combineLensParts(state.make,state.model) || '—';
          const exposureText=[state.aperture,state.shutter,formatIsoText(state.iso)].filter(Boolean).join('  ·  ') || '—';
          const sizeText=analysis.width && analysis.height
            ? `${analysis.width} × ${analysis.height}  ·  ${analysis.megapixels.toFixed(1)} MP`
            : '—';
          const dateTime=[dateText(state),state.time].filter(Boolean).join('  ') || '—';

          const photoY=m+(contentHeight-photoH)/2;
          drawPhoto(ctx,m,photoY,photoW,photoH,radius);

          const panelX=m+photoW+panelGap;
          let yy=m+24;
          drawText(ctx,'PHOTO DATA',panelX,yy,18,fg,'800',fonts.meta);
          line(ctx,panelX,yy+18,panelX+panelWidth,yy+18,'rgba(0,0,0,0.26)',1);
          yy+=60;

          if(isActiveSetting(state,'showTitle')){
            drawManagedFittedText(ctx,state,'title',state.title,panelX,yy,panelWidth,30,16,fg,'700',fonts.title);
            yy+=40;
          }
          if(isActiveSetting(state,'showLocation')){
            drawManagedFittedText(ctx,state,'location',state.location,panelX,yy,panelWidth,16,10,locationColor,'500',fonts.meta);
            yy+=34;
          }

          if(isActiveSetting(state,'showExif')){
            const rows=[
              ['CAMERA',cameraText],['LENS',state.lens||'—'],['DATE',dateTime],
              ['EXPOSURE',exposureText],['FOCAL LENGTH',state.focal||'—'],
              ['SIZE',sizeText],['RATIO',analysis.ratio]
            ];
            rows.forEach(([label,value])=>{
              rowLabel(label,panelX,yy);
              rowValue(value,panelX+122,yy,panelWidth-122);
              yy+=32;
            });
          }

          yy+=10;
          drawText(ctx,'RGB HISTOGRAM',panelX,yy,12,muted,'700',fonts.meta);
          yy+=14;
          drawPhotoDataHistogram(ctx,analysis,panelX,yy,panelWidth,142);
          yy+=174;
          drawText(ctx,'DOMINANT COLORS',panelX,yy,12,muted,'700',fonts.meta);
          yy+=14;
          drawPhotoDataPalette(ctx,analysis,panelX,yy,panelWidth,34,8);
          yy+=56;
          drawText(ctx,`AVERAGE  ${analysis.average}`,panelX,yy,12,muted,'700',fonts.meta);
          ctx.fillStyle=analysis.average;
          ctx.fillRect(panelX+panelWidth-36,yy-13,36,18);
          yy+=34;
          drawText(ctx,`BRIGHTNESS  ${analysis.brightness}%`,panelX,yy,12,muted,'700',fonts.meta);
          drawPhotoDataBrightness(ctx,analysis,panelX,yy+12,panelWidth,fg);
        }
      };
    }


    if(layout === 'multiframe'){
      const gap = Math.max(0, Number(state.multiFrameGap) || 0);
      const variant = state.multiFrameLayout || 'hero_two_landscape';
      const items = getOrderedMultiFrameItems(getMultiFrameCount(variant));
      const geometry = getMultiFrameGeometry(variant, items, gap);
      const W = geometry.innerW + m * 2;
      const H = geometry.innerH + m * 2;
      return {
        width: W,
        height: H,
        draw(ctx){
          drawFrameSurface(ctx, 0, 0, W, H, frameColor);
          geometry.slots.forEach((slot, index) => {
            const item = items[index] || null;
            const box = {x:slot.x + m, y:slot.y + m, w:slot.w, h:slot.h};
            const record = item ? requestCollageImage(item.url) : null;
            if(record && record.status === 'loaded'){
              drawSourceContain(ctx, record.img, box.x, box.y, box.w, box.h);
            }else{
              drawMultiFramePlaceholder(ctx, box.x, box.y, box.w, box.h, index, fonts);
            }
          });
        }
      };
    }

    if(layout === 'brush'){
      const W = photoW + m * 2;
      const H = photoH + m * 2;
      return {
        width: W,
        height: H,
        draw(ctx){
          drawFrameSurface(ctx, 0, 0, W, H, frameColor);
          drawBrushPhoto(ctx, m, m, photoW, photoH, state.brushStyle || 'A');
        }
      };
    }

    // Journal B
    const titleSize = 36;
    const locationSize = 22;
    const topGap = (isActiveSetting(state,'showTitle') || isActiveSetting(state,'showLocation')) ? Math.round(titleSize * 0.5) : 0;
    const headerBand = (isActiveSetting(state,'showTitle') || isActiveSetting(state,'showLocation')) ? titleSize + topGap : 0;
    const photoY = m + headerBand;
    const photoX = m;

    const metaGap = 44;
    const logoBlockHeight = 34;
    const logoToTextGap = 20;
    const modelFontSize = 25;
    const contentW = photoW;
    const leftW = Math.min(340, contentW * 0.32);
    const rx = m + leftW + 44;
    const rw = (m + photoW) - rx;

    const promptH = isActiveSetting(state,'showPrompt') ? 28 : 0;
    const thoughtLines = isActiveSetting(state,'showThought') ? wrapLines(measureCtx, state.thought, rw, 24, fonts.body, '400', 5).length : 0;
    const noteLines = isActiveSetting(state,'showNote') ? wrapLines(measureCtx, state.note, rw, 24, fonts.body, '400', 4).length : 0;
    const thoughtH = isActiveSetting(state,'showThought') ? 24 + thoughtLines * 34 + 16 : 0;
    const noteH = isActiveSetting(state,'showNote') ? 24 + noteLines * 34 : 0;
    const rightContentH = promptH + thoughtH + noteH;
    const journalBrandVisible = isActiveSetting(state,'showLogo');
    const journalExifVisible = isActiveSetting(state,'showExif');
    const logoSectionH = journalBrandVisible ? logoBlockHeight + logoToTextGap : 0;
    const exifSectionH = journalExifVisible ? modelFontSize + metaGap * 3 + 18 : 0;
    const leftContentH = logoSectionH + exifSectionH;
    const contentH = Math.max(rightContentH, leftContentH);
    const footerBand = (isActiveSetting(state,'showProject') || isActiveSetting(state,'showRating')) ? 56 : 12;

    const W = photoW + m * 2;
    const H = photoY + photoH + 34 + contentH + 30 + footerBand + m;

    return {
      width: W, height: H,
      draw(ctx){
        const fg = lightPalette.title;
        const bodyFg = lightPalette.body;
        const muted = lightPalette.meta;
        ctx.fillStyle = frameColor;
        ctx.fillRect(0,0,W,H);

        if(isActiveSetting(state,'showTitle')){
          drawManagedText(ctx, state, 'title', state.title, m, m + titleSize, titleSize, fg, '700', fonts.title);
        }
        if(isActiveSetting(state,'showLocation')){
          drawManagedText(ctx, state, 'location', state.location, W - m, m + locationSize + 8, locationSize, fg, '600', fonts.title, 'right');
        }

        drawPhoto(ctx, photoX, photoY, photoW, photoH, radius);
        line(ctx, m, photoY + photoH + 26, W - m, photoY + photoH + 26, '#cfc5b8', 1);

        const colsY = photoY + photoH + 56;
        const dividerX = m + leftW;
        line(ctx, dividerX, colsY - 18, dividerX, H - footerBand - 10, '#cfc5b8', 1);

        const brandVisible = isActiveSetting(state, 'showLogo');
        const exifVisible = isActiveSetting(state, 'showExif');
        const logoY = colsY - 8;
        let logoBottom = colsY;

        if(brandVisible){
          const brandBox = drawBrand(
            ctx,
            theme,
            state,
            m,
            logoY,
            250,
            logoBlockHeight,
            fonts.meta,
            'left',
            lightPalette.meta
          );
          logoBottom = logoY + Math.max(brandBox.h || 0, logoBlockHeight);
        }

        /*
          The first metadata line uses a baseline.  Adding only a fixed row gap
          can make tall fonts overlap the logo, so the baseline is calculated
          from the actual logo block bottom plus a separate visual gap and the
          model font's ascent allowance.
        */
        const metaStartY = brandVisible
          ? logoBottom + logoToTextGap + modelFontSize * 0.82
          : colsY + modelFontSize * 0.82;

        const metaTextWidth = Math.max(120, leftW - 22);

        if(exifVisible){
          drawManagedFittedText(ctx, state, 'exif', state.model, m, metaStartY, metaTextWidth, modelFontSize, 14, lightPalette.meta, '600', fonts.meta);
          drawManagedFittedText(ctx, state, 'exif', state.lens, m, metaStartY + metaGap, metaTextWidth, 22, 12, lightPalette.meta, '400', fonts.meta);
          drawManagedFittedText(ctx, state, 'exif', exifLine(state), m, metaStartY + metaGap * 2, metaTextWidth, 21, 11, lightPalette.meta, '400', fonts.meta);
          drawManagedFittedText(ctx, state, 'exif', `${dateText(state)}  ${state.time}`, m, metaStartY + metaGap * 3, metaTextWidth, 21, 11, lightPalette.meta, '400', fonts.meta);
        }

        let yy = colsY;
        if(isActiveSetting(state,'showPrompt')){
          drawManagedText(ctx, state, 'body', state.promptText, rx, yy, 18, lightPalette.meta, '700', fonts.meta, 'left', false, 'prompt');
          yy += 28;
        }
        if(isActiveSetting(state,'showThought')){
          drawManagedText(ctx, state, 'meta', 'THOUGHT', rx, yy, 15, muted, '700', fonts.meta, 'left', false, 'thought');
          yy += 24;
          yy += drawManagedWrappedText(ctx, state, 'body', state.thought, rx, yy, rw, 34, 24, bodyFg, fonts.body, '400', 5, 'left', 'thought');
          yy += 16;
        }
        if(isActiveSetting(state,'showNote')){
          if(isActiveSetting(state,'showThought')){
            line(ctx, rx, yy, rx + rw, yy, '#cfc5b8', 1);
            yy += 22;
          }
          drawManagedText(ctx, state, 'meta', 'NOTE', rx, yy, 15, muted, '700', fonts.meta, 'left', false, 'note');
          yy += 24;
          drawManagedWrappedText(ctx, state, 'body', state.note, rx, yy, rw, 34, 24, bodyFg, fonts.body, '400', 4, 'left', 'note');
        }

        if(isActiveSetting(state,'showProject') || isActiveSetting(state,'showRating')){
          line(ctx, m, H - footerBand - 8, W - m, H - footerBand - 8, '#cfc5b8', 1);
          const footerY = H - 16;
          if(isActiveSetting(state,'showProject')){
            drawManagedText(ctx, state, 'meta', 'PROJECT', m, footerY, 15, muted, '700', fonts.meta, 'left', false, 'project');
            drawManagedText(ctx, state, 'body', state.project, m + 92, footerY, 23, fg, '700', fonts.title, 'left', false, 'project');
          }
          if(isActiveSetting(state,'showRating')){
            const ratingAdj = getElementAdjustments(state, 'meta', 'rating', lightPalette.meta);
            const starSize = 23 * ratingAdj.scale;
            const estimatedStarWidth = starSize * 5.2;
            drawText(ctx, 'RATING', W - m - estimatedStarWidth - 78 + ratingAdj.dx, footerY + ratingAdj.dy, 15 * ratingAdj.scale, muted, '700', fonts.meta);
            stars(ctx, W - m + ratingAdj.dx, footerY + ratingAdj.dy, Number(state.rating), ratingAdj.color, starSize, fonts.meta, 'right');
          }
        }
      }
    };
  }

  async function resetSettingsToDefaults(){
    const confirmed = window.confirm(
      '사진, EXIF, 입력한 제목과 본문은 유지하고 레이아웃 및 스타일 설정만 기본값으로 되돌릴까요?'
    );
    if(!confirmed) return;

    layout = 'journal';
    elementLayoutState = {};

    const values = {
      theme:'auto',
      customLogoDataUrl:'',
      customLogoFileName:'',
      titleFont:"'Pretendard', sans-serif",
      bodyFont:"'Source Han Sans KR', 'Noto Sans KR', sans-serif",
      metaFont:"'Pretendard', sans-serif",
      textColorMode:'auto',
      titleColor:'#171717',
      bodyColor:'#171717',
      metaColor:'#5f5f5f',
      locationColor:'#5f5f5f',
      posterTitleDirection:'horizontal',
      posterBodyDirection:'horizontal',
      posterTitleSize:'66',
      posterBodySize:'22',
      posterTitleX:'0',
      posterTitleY:'72',
      posterBodyX:'0',
      posterBodyY:'84',
      titleScale:'100',
      titleOffsetX:'0',
      titleOffsetY:'0',
      bodyScale:'100',
      bodyOffsetX:'0',
      bodyOffsetY:'0',
      locationScale:'100',
      locationOffsetX:'0',
      locationOffsetY:'0',
      exifScale:'100',
      exifOffsetX:'0',
      exifOffsetY:'0',
      frameColor:'#f3eee4',
      margin:'52',
      radius:'0',
      brushStyle:'A',
      multiFrameLayout:'hero_two_landscape',
      multiFrameGap:'12',
      creatorFormat:'copyright',
      creatorColor:'#ffffff',
      watermarkColor:'#ffffff'
    };

    Object.entries(values).forEach(([id, value]) => {
      const element = $(id);
      if(element) element.value = value;
    });

    const checks = {
      showTitle:true,
      showLocation:true,
      showThought:true,
      showNote:true,
      showProject:true,
      showRating:true,
      showPrompt:false,
      showLogo:true,
      showExif:true,
      showCreator:false,
      showWatermark:false
    };

    Object.entries(checks).forEach(([id, checked]) => {
      const element = $(id);
      if(element) element.checked = checked;
    });

    $('downloadResult').hidden = true;
    normalizeFontSelections();
    document.querySelectorAll('.template').forEach(button => {
      button.classList.toggle('active', button.dataset.layout === layout);
    });
    stylesForLayout(layout);
    renderedElementLayout = null;
    updateControlVisibility();
    renderElementControls(true);
    syncDesignStateAfterChange({refreshList:true});
    saveState();
    await ensureSelectedUserFonts({render:false, silent:true});
    renderPreview();
    $('statusText').textContent = '설정 기본값 복원 완료';
  }

  function renderPreview(){
    const state = getState();
    stylesForLayout(layout);
    updateControlVisibility();

    const measureCanvas = document.createElement('canvas');
    const mctx = measureCanvas.getContext('2d');
    const model = buildModel(state, mctx);
    const targetLongEdge = 1200;
    const scale = targetLongEdge / Math.max(model.width, model.height);

    previewCanvas.width = Math.round(model.width * scale);
    previewCanvas.height = Math.round(model.height * scale);
    previewCtx.setTransform(scale, 0, 0, scale, 0, 0);
    model.draw(previewCtx);
    drawUniversalOverlays(previewCtx, state, model);

    $('statusText').textContent = '준비됨';
    $('canvasInfo').textContent = `${previewCanvas.width} × ${previewCanvas.height} preview`;
  }

  function isSafariBrowser(){
    const ua = navigator.userAgent;
    return /Safari/i.test(ua) && !/Chrome|Chromium|CriOS|Edg|OPR|Android/i.test(ua);
  }

  function safeCanvasPixelLimit(){
    return isSafariBrowser() ? 16000000 : 48000000;
  }

  function selectedLogoReady(state){
    const watermarkRecord = state.showWatermark && state.watermarkDataUrl ? getWatermarkImage(state.watermarkDataUrl) : null;
    if(watermarkRecord && !watermarkRecord.loaded && !watermarkRecord.failed) return false;

    if(layout === 'stamp' || !isActiveSetting(state, 'showLogo')){
      return true;
    }

    const theme = effectiveTheme(state);
    if(theme.textOnly) return true;
    const record = requestLocalLogo(theme);

    /*
      Export is intentionally synchronous so Safari keeps the original
      button-click permission.  If an image logo is still loading, the user
      must click once more after it has appeared in the preview.
    */
    return !record || record.loaded || record.failed;
  }

  function dataUrlToBlob(dataUrl){
    const comma = dataUrl.indexOf(',');
    if(comma < 0) return null;

    const header = dataUrl.slice(0, comma);
    const payload = dataUrl.slice(comma + 1);
    const mimeMatch = header.match(/^data:([^;]+)/i);
    const mime = mimeMatch ? mimeMatch[1] : 'image/jpeg';

    const binary = atob(payload);
    const bytes = new Uint8Array(binary.length);

    for(let i=0; i<binary.length; i++){
      bytes[i] = binary.charCodeAt(i);
    }

    return new Blob([bytes], {type:mime});
  }


  function directoryPickerSupported(){
    return typeof window.showDirectoryPicker === 'function';
  }

  function updateSaveDirStatus(message=''){
    const el = $('saveDirStatus');
    if(!el) return;
    if(message){
      el.textContent = message;
      return;
    }
    if(saveDirectoryHandle){
      el.textContent = `저장 폴더: ${saveDirectoryHandle.name} · 현재/전체 저장 시 이 폴더에 직접 저장`;
    }else if(directoryPickerSupported()){
      el.textContent = '저장 폴더 미선택 · 선택하면 JPEG/일괄 결과를 해당 폴더에 직접 저장';
    }else{
      el.textContent = '이 브라우저는 폴더 직접 저장을 지원하지 않습니다. 일반 다운로드/ZIP으로 저장됩니다.';
    }
  }

  async function chooseSaveDirectory(){
    if(!directoryPickerSupported()){
      alert('이 브라우저는 저장 폴더 직접 선택을 지원하지 않습니다. Chrome 또는 Edge 사용을 권장합니다.');
      updateSaveDirStatus();
      return null;
    }
    try{
      const handle = await window.showDirectoryPicker({mode:'readwrite'});
      saveDirectoryHandle = handle;
      updateSaveDirStatus();
      $('statusText').textContent = `저장 폴더 선택 완료: ${handle.name}`;
      return handle;
    }catch(error){
      if(error && error.name === 'AbortError'){
        $('statusText').textContent = '저장 폴더 선택 취소';
        return null;
      }
      console.error('Directory picker failed:', error);
      alert(`저장 폴더를 선택하지 못했습니다.

${error && error.message ? error.message : String(error)}`);
      return null;
    }
  }

  function clearSaveDirectory(){
    saveDirectoryHandle = null;
    updateSaveDirStatus();
    $('statusText').textContent = '저장 폴더 선택 해제';
  }

  async function ensureDirectoryPermission(handle){
    if(!handle) return false;
    if(handle.queryPermission){
      const current = await handle.queryPermission({mode:'readwrite'});
      if(current === 'granted') return true;
    }
    if(handle.requestPermission){
      const next = await handle.requestPermission({mode:'readwrite'});
      return next === 'granted';
    }
    return false;
  }

  function splitFileName(name){
    const match = /^(.*?)(\.[^.]+)?$/.exec(name || 'file');
    return {base: match?.[1] || 'file', ext: match?.[2] || ''};
  }

  async function getUniqueFileHandle(dirHandle, fileName){
    const {base, ext} = splitFileName(fileName);
    let candidate = `${base}${ext}`;
    let count = 1;
    while(true){
      try{
        await dirHandle.getFileHandle(candidate, {create:false});
        candidate = `${base}_${count}${ext}`;
        count += 1;
      }catch(error){
        const handle = await dirHandle.getFileHandle(candidate, {create:true});
        return {handle, fileName: candidate};
      }
    }
  }

  async function writeBlobToDirectory(dirHandle, fileName, blob){
    const {handle, fileName: finalName} = await getUniqueFileHandle(dirHandle, fileName);
    const writable = await handle.createWritable();
    await writable.write(blob);
    await writable.close();
    return finalName;
  }

  async function getExportDirectoryHandle({promptIfNeeded=true} = {}){
    if(!directoryPickerSupported()) return null;
    if(saveDirectoryHandle){
      const ok = await ensureDirectoryPermission(saveDirectoryHandle);
      if(ok) return saveDirectoryHandle;
    }
    if(!promptIfNeeded) return null;
    const handle = await chooseSaveDirectory();
    if(!handle) return null;
    const ok = await ensureDirectoryPermission(handle);
    if(!ok){
      alert('선택한 폴더에 쓰기 권한을 얻지 못했습니다. 일반 다운로드 방식으로 진행합니다.');
      return null;
    }
    return handle;
  }

  function prepareAndStartDownload(blob, fileName, message, downloadLabel='다운로드'){
    if(preparedDownloadUrl){
      URL.revokeObjectURL(preparedDownloadUrl);
    }

    preparedDownloadUrl = URL.createObjectURL(blob);

    const panel = $('downloadResult');
    const link = $('preparedDownloadLink');
    const messageEl = $('downloadMessage');

    link.href = preparedDownloadUrl;
    link.download = fileName;
    link.textContent = downloadLabel;
    messageEl.textContent = message;
    panel.hidden = false;

    /*
      This click runs in the same synchronous call stack as the user's export
      button click.  That preserves Safari's user-activation permission.
      The visible link remains available as a manual fallback.
    */
    const temporaryLink = document.createElement('a');
    temporaryLink.href = preparedDownloadUrl;
    temporaryLink.download = fileName;
    temporaryLink.style.display = 'none';
    document.body.appendChild(temporaryLink);

    try{
      temporaryLink.click();
    }finally{
      temporaryLink.remove();
    }
  }


  function generateJPEGBlobForState(state, mode){
    const previousLayout = layout;
    layout = state.layout || layout;
    try{
      const measureCanvas = document.createElement('canvas');
      const measureContext = measureCanvas.getContext('2d');
      if(!measureContext) throw new Error('Canvas 측정 컨텍스트를 만들 수 없습니다.');

      const model = buildModel(state, measureContext);
      const requestedScale = mode === 'original'
        ? image.naturalWidth / 1000
        : 1600 / Math.max(model.width, model.height);

      const pixelLimit = safeCanvasPixelLimit();
      const requestedPixels = model.width * model.height * requestedScale * requestedScale;
      let scale = requestedScale;
      let sizeWasReduced = false;

      if(requestedPixels > pixelLimit){
        scale = Math.sqrt(pixelLimit / (model.width * model.height));
        sizeWasReduced = true;
      }

      const out = document.createElement('canvas');
      out.width = Math.max(1, Math.round(model.width * scale));
      out.height = Math.max(1, Math.round(model.height * scale));

      const outputContext = out.getContext('2d');
      if(!outputContext) throw new Error('출력 Canvas를 만들 수 없습니다.');

      outputContext.setTransform(scale, 0, 0, scale, 0, 0);
      model.draw(outputContext);
      drawUniversalOverlays(outputContext, state, model);

      const dataUrl = out.toDataURL('image/jpeg', 0.95);
      if(!dataUrl || dataUrl === 'data:,') throw new Error('브라우저가 JPEG 데이터를 만들지 못했습니다.');

      const blob = dataUrlToBlob(dataUrl);
      if(!blob || blob.size === 0) throw new Error('생성된 JPEG 데이터가 비어 있습니다.');

      return {blob, width: out.width, height: out.height, sizeWasReduced};
    }finally{
      layout = previousLayout;
    }
  }

  async function exportAllJPEG(mode){
    if(!photoItems.length){
      alert('먼저 사진을 불러와 주세요.');
      return;
    }

    const canZip = typeof JSZip !== 'undefined';
    const canDirectorySave = directoryPickerSupported();
    if(!canZip && !canDirectorySave){
      alert('이 브라우저에서는 ZIP과 폴더 저장을 모두 사용할 수 없습니다. Chrome 또는 Edge 사용을 권장합니다.');
      return;
    }

    if(!selectedUserFontsAreReady()){
      ensureSelectedUserFonts({render:true, silent:false});
      alert(pendingFontLoads ? '선택한 추가 폰트를 불러오는 중입니다. 적용 완료 후 다시 저장하세요.' : '선택한 추가 폰트 파일을 먼저 불러오거나 assets/fonts 폴더에 넣어주세요.');
      return;
    }

    syncCurrentPhotoValues();
    $('downloadResult').hidden = true;

    const initialState = getState();
    const originalSelectedId = selectedPhotoId;
    const originalStatus = $('statusText').textContent;
    const dirHandle = await getExportDirectoryHandle({promptIfNeeded:false});
    const useDirectorySave = !!dirHandle;

    if(!useDirectorySave && !canZip){
      alert('ZIP 라이브러리를 불러오지 못했습니다. 먼저 저장 폴더를 선택한 뒤 다시 시도해 주세요.');
      return;
    }

    const zip = useDirectorySave ? null : new JSZip();
    let reducedCount = 0;
    let savedCount = 0;

    try{
      for(let index=0; index<photoItems.length; index++){
        const item = photoItems[index];
        $('statusText').textContent = `일괄 ${mode === 'original' ? '원본' : '웹용'} ${useDirectorySave ? '저장' : '렌더링'} 중… (${index + 1}/${photoItems.length})`;
        await loadPreviewImageFromItem(item);
        const state = buildStateForPhoto(initialState, item);
        const rendered = generateJPEGBlobForState(state, mode);
        if(rendered.sizeWasReduced) reducedCount += 1;
        const base = (item.name || `photo_${index+1}`).replace(/\.[^.]+$/, '');
        const suffix = rendered.sizeWasReduced && mode === 'original' ? 'original_browser_safe' : mode;
        const finalFileName = `${base}_${state.layout || layout}_${suffix}.jpg`;

        if(useDirectorySave){
          await writeBlobToDirectory(dirHandle, finalFileName, rendered.blob);
          savedCount += 1;
        }else{
          zip.file(finalFileName, rendered.blob, {binary:true});
        }

        await new Promise(resolve => setTimeout(resolve, 0));
      }

      if(useDirectorySave){
        const detail = reducedCount > 0 && mode === 'original'
          ? `${savedCount}장 저장 완료 · ${reducedCount}장은 브라우저 안전 크기로 자동 축소`
          : `${savedCount}장 저장 완료`;
        $('downloadResult').hidden = true;
        $('statusText').textContent = '일괄 폴더 저장 완료';
        $('canvasInfo').textContent = `${savedCount} images saved`;
        updateSaveDirStatus(`저장 폴더: ${dirHandle.name} · ${detail}`);
      }else{
        $('statusText').textContent = 'ZIP 묶는 중…';
        const zipBlob = await zip.generateAsync({type:'blob', streamFiles:true}, meta => {
          $('statusText').textContent = `ZIP 묶는 중… ${Math.round(meta.percent)}%`;
        });

        const zipName = `FrameNote_${batchApplyMode ? layout : 'individual'}_${mode}_batch_${photoItems.length}images.zip`;
        const detail = reducedCount > 0 && mode === 'original'
          ? `원본 모드 중 ${reducedCount}장은 브라우저 안전 크기로 자동 축소`
          : `${photoItems.length}장 순차 처리 완료`;
        prepareAndStartDownload(zipBlob, zipName, `${detail} · 자동 저장이 안 되면 다운로드 버튼을 눌러주세요.`, 'ZIP 다운로드');
        $('statusText').textContent = '일괄 ZIP 생성 완료';
        $('canvasInfo').textContent = `${photoItems.length} images batched`;
      }
    }catch(error){
      console.error('Batch export failed:', error);
      $('statusText').textContent = useDirectorySave ? '일괄 폴더 저장 실패' : '일괄 ZIP 생성 실패';
      alert(`일괄 내보내기에 실패했습니다.

${error && error.message ? error.message : String(error)}`);
    }finally{
      if(originalSelectedId){
        try{ await selectPhotoById(originalSelectedId, {preserveCurrent:false}); }catch(error){ console.warn(error); }
      }
      $('statusText').textContent = $('statusText').textContent.includes('실패') || $('statusText').textContent.includes('완료') ? $('statusText').textContent : originalStatus;
    }
  }

  function nativeFileShareSupported(){
    if(!navigator.share || !navigator.canShare) return false;
    try{
      const probe = new File([new Blob(['x'], {type:'image/jpeg'})], 'framenote.jpg', {type:'image/jpeg'});
      return navigator.canShare({files:[probe]});
    }catch(error){
      return false;
    }
  }

  function updateNativeShareUI(){
    const supported = nativeFileShareSupported();
    const likelyIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) || (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1);
    ['shareOriginalBtn','shareWebBtn'].forEach(id => { const el=$(id); if(el) el.hidden = !(supported && likelyIOS); });
    const guide = $('iosShareGuide');
    if(guide) guide.hidden = !(supported && likelyIOS);
  }

