  function parseExif(arrayBuffer){
    const view = new DataView(arrayBuffer);
    if(view.getUint16(0,false) !== 0xFFD8) return {};
    let offset = 2;
    while(offset < view.byteLength){
      if(view.getUint8(offset) !== 0xFF) break;
      const marker = view.getUint8(offset + 1);
      const len = view.getUint16(offset + 2, false);
      if(marker === 0xE1 && getString(view, offset + 4, 4) === 'Exif'){
        return parseTiff(view, offset + 10);
      }
      offset += 2 + len;
    }
    return {};
  }

  function getString(view, offset, length){
    let out = '';
    for(let i=0;i<length;i++) out += String.fromCharCode(view.getUint8(offset+i));
    return out;
  }

  function parseTiff(v, tiff){
    const little = v.getUint16(tiff,false) === 0x4949;
    const u16 = o => v.getUint16(o,little);
    const u32 = o => v.getUint32(o,little);
    const out = {};
    function readValue(entry, type, count){
      const valueOffset = entry + 8;
      const inPlace = (type === 3 && count <= 2) || (type === 4 && count === 1);
      const off = inPlace ? valueOffset : tiff + u32(valueOffset);
      if(type === 2) return getString(v, off, count).replace(/\0/g,'').trim();
      if(type === 3) return u16(off);
      if(type === 4) return u32(off);
      if(type === 5){
        const values = [];
        for(let index = 0; index < count; index++){
          const n = u32(off + index * 8), d = u32(off + index * 8 + 4);
          values.push(d ? n / d : 0);
        }
        return count === 1 ? values[0] : values;
      }
      if(type === 10){
        const values = [];
        for(let index = 0; index < count; index++){
          const n = v.getInt32(off + index * 8,little), d = v.getInt32(off + index * 8 + 4,little);
          values.push(d ? n / d : 0);
        }
        return count === 1 ? values[0] : values;
      }
      return null;
    }
    function readIFD(off){
      const n = u16(off);
      for(let i=0;i<n;i++){
        const e = off + 2 + i*12;
        const tag = u16(e), type = u16(e+2), count = u32(e+4), val = readValue(e,type,count);
        if(tag === 0x010F) out.make = val;
        if(tag === 0x0110) out.model = val;
        if(tag === 0x0132) out.datetime = val;
        if(tag === 0x8769) readIFD(tiff + u32(e+8));
        if(tag === 0xA432) out.lensInfo = val;
        if(tag === 0xA434) out.lens = val;
        if(tag === 0x829D) out.aperture = val;
        if(tag === 0x829A) out.exposure = val;
        if(tag === 0x8827) out.iso = val;
        if(tag === 0x920A) out.focal = val;
        if(tag === 0x9003) out.datetime = val;
      }
    }
    readIFD(tiff + u32(tiff + 4));
    return out;
  }

  function shutterText(v){
    if(!v) return '';
    if(v >= 1) return `${v.toFixed(v < 10 ? 1 : 0)}s`;
    return `1/${Math.round(1/v)}`;
  }

  function applyExif(ex){
    if(ex.make) $('make').value = ex.make;
    if(ex.model) $('model').value = ex.model;
    const lensDisplay = normalizeExifText(ex.lens);
    if(lensDisplay) $('lens').value = lensDisplay;
    if(ex.focal) $('focal').value = `${Math.round(ex.focal*10)/10}mm`;
    if(ex.aperture) $('aperture').value = `F${Math.round(ex.aperture*10)/10}`;
    if(ex.exposure) $('shutter').value = shutterText(ex.exposure);
    if(ex.iso) $('iso').value = formatIsoText(ex.iso);
    if(ex.datetime){
      const p = String(ex.datetime).split(' ');
      if(p[0]) $('date').value = p[0].replaceAll(':','-');
      if(p[1]) $('time').value = p[1].slice(0,5);
    }
  }

